import React, { useState, useRef, useMemo } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, Legend } from 'recharts';
import { AlertCircle, Package, ShoppingBag, X, Upload, Download, TrendingUp, Crown, Moon, Sun, Plus, Calendar, Filter, Palette } from 'lucide-react';
import { AppView, AppTheme } from '../types';

const Dashboard: React.FC = () => {
  const { 
    inventory, sales, orders, setCurrentView, setInventorySearchTerm, 
    exportData, importData, formatDate, businessConfig, 
    isPaid, togglePaidStatus, isDarkMode, toggleDarkMode, addCategory,
    theme, setTheme
  } = usePharmacy();

  const [showRevenueDetails, setShowRevenueDetails] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showThemeModal, setShowThemeModal] = useState(false);
  const [newCategory, setNewCategory] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sales Analysis State
  const [salesFilter, setSalesFilter] = useState('Today');
  const [customDate, setCustomDate] = useState(new Date().toISOString().split('T')[0]);

  const totalRevenue = sales.reduce((acc, sale) => acc + sale.totalAmount, 0);
  const totalProfit = sales.reduce((acc, sale) => acc + (sale.profit || 0), 0);

  const lowStockItems = inventory.filter(i => i.quantity < 50);
  const expiringSoon = inventory.filter(i => {
    if(!i.expiryDate) return false;
    const daysUntilExpiry = Math.ceil((new Date(i.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    return daysUntilExpiry < 90 && daysUntilExpiry > 0;
  });

  // Calculate Product Sales based on Filter
  const { productSalesList, totalItemsSold } = useMemo(() => {
    const today = new Date();

    const filtered = sales.filter(sale => {
        const saleDate = new Date(sale.date);

        if (salesFilter === 'Today') {
            return saleDate.toDateString() === today.toDateString();
        }
        if (salesFilter === 'Yesterday') {
            const yesterday = new Date(today);
            yesterday.setDate(yesterday.getDate() - 1);
            return saleDate.toDateString() === yesterday.toDateString();
        }
        if (salesFilter === 'This Month') {
            return saleDate.getMonth() === today.getMonth() && saleDate.getFullYear() === today.getFullYear();
        }
        if (salesFilter === 'Last Month') {
            const d = new Date();
            d.setDate(1); 
            d.setMonth(d.getMonth() - 1);
            return saleDate.getMonth() === d.getMonth() && saleDate.getFullYear() === d.getFullYear();
        }
        if (salesFilter === 'Custom') {
            return saleDate.toDateString() === new Date(customDate).toDateString();
        }
        return true;
    });

    const map = new Map<string, number>();
    let total = 0;

    filtered.forEach(sale => {
        sale.items.forEach(item => {
            const current = map.get(item.name) || 0;
            map.set(item.name, current + item.cartQuantity);
            total += item.cartQuantity;
        });
    });

    const list = Array.from(map.entries())
        .map(([name, quantity]) => ({ name, quantity }))
        .sort((a, b) => b.quantity - a.quantity);

    return { productSalesList: list, totalItemsSold: total };
  }, [sales, salesFilter, customDate]);

  const salesData = sales.slice(0, 7).map(s => ({
    name: formatDate(s.date),
    amount: s.totalAmount
  })).reverse();

  const handleBackup = () => {
    const data = exportData();
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${businessConfig?.details.name.replace(/\s+/g, '_')}_backup.json`;
    a.click();
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
          importData(event.target.result as string);
        }
      };
      reader.readAsText(file);
    }
  };

  const handleAlertClick = (searchTerm: string) => {
    setInventorySearchTerm(searchTerm);
    setCurrentView(AppView.INVENTORY);
  };

  const handleTogglePaid = () => {
    togglePaidStatus();
  };

  const handleAddCategory = () => {
    if (newCategory.trim()) {
      addCategory(newCategory.trim());
      setNewCategory('');
      setShowCategoryModal(false);
    }
  };

  const dailySales = sales.reduce((acc: any, sale) => {
    const dateKey = new Date(sale.date).toISOString().split('T')[0];
    if (!acc[dateKey]) acc[dateKey] = { date: dateKey, revenue: 0, profit: 0 };
    acc[dateKey].revenue += sale.totalAmount;
    acc[dateKey].profit += sale.profit || 0;
    return acc;
  }, {});

  const dailyData = Object.values(dailySales)
    .sort((a: any, b: any) => new Date(a.date).getTime() - new Date(b.date).getTime())
    .map((d: any) => ({ ...d, date: formatDate(d.date) }));

  const currency = businessConfig?.details.currency || '$';

  // Chart Styles based on Dark Mode
  const chartAxisColor = isDarkMode ? '#9ca3af' : '#4b5563';
  const chartGridColor = isDarkMode ? '#374151' : '#e5e7eb';
  const tooltipStyle = isDarkMode 
    ? { backgroundColor: '#1f2937', borderColor: '#374151', color: '#f3f4f6' }
    : { backgroundColor: '#fff', borderColor: '#e5e7eb', color: '#1f2937' };

  const ThemeButton = ({ t, color }: { t: AppTheme, color: string }) => (
    <button 
      onClick={() => setTheme(t)}
      className={`w-10 h-10 rounded-full border-2 flex items-center justify-center transition ${theme === t ? 'border-gray-800 dark:border-white scale-110' : 'border-transparent hover:scale-105'}`}
      style={t === 'gradient' ? { background: 'linear-gradient(135deg, #2dd4bf, #3b82f6, #8b5cf6)' } : { backgroundColor: color }}
      title={t.charAt(0).toUpperCase() + t.slice(1)}
    >
      {theme === t && <span className="w-2 h-2 bg-white rounded-full"></span>}
    </button>
  );

  return (
    <div className="p-4 space-y-6">
      <div className="flex flex-col xl:flex-row justify-between items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Dashboard</h2>
           <p className="text-sm text-gray-500 dark:text-gray-400">Welcome back, here is what's happening today.</p>
        </div>

        <div className="flex flex-wrap items-center gap-2 w-full xl:w-auto justify-end">
           {/* Theme Toggle */}
           <button 
             onClick={() => setShowThemeModal(!showThemeModal)}
             className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition shadow-sm text-gray-700 dark:text-gray-200 relative"
           >
             <Palette size={16} className="text-primary-600"/>
             <span className="hidden sm:inline">Theme</span>
             {showThemeModal && (
                <div className="absolute top-full right-0 mt-2 p-3 bg-white dark:bg-gray-800 rounded-xl shadow-xl border border-gray-200 dark:border-gray-700 flex gap-2 z-50 animate-in fade-in zoom-in duration-200">
                    <ThemeButton t="teal" color="#14b8a6" />
                    <ThemeButton t="blue" color="#3b82f6" />
                    <ThemeButton t="violet" color="#8b5cf6" />
                    <ThemeButton t="rose" color="#f43f5e" />
                    <ThemeButton t="orange" color="#f97316" />
                    <ThemeButton t="gradient" color="" />
                </div>
             )}
           </button>

           {/* Dark Mode Toggle */}
           <button 
             onClick={toggleDarkMode}
             className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition shadow-sm text-gray-700 dark:text-gray-200"
           >
             {isDarkMode ? <Sun size={16} className="text-yellow-400"/> : <Moon size={16} className="text-gray-600"/>}
             <span className="hidden sm:inline">{isDarkMode ? 'Light' : 'Dark'}</span>
           </button>

           {/* Pro Toggle */}
           <button 
             onClick={handleTogglePaid}
             className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-bold shadow-sm transition border ${isPaid ? 'bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-800' : 'bg-white dark:bg-gray-800 text-gray-500 dark:text-gray-400 border-gray-200 dark:border-gray-700'}`}
           >
              <Crown size={16}/> {isPaid ? 'Pro' : 'Free'}
           </button>

           <div className="h-6 w-px bg-gray-300 dark:bg-gray-700 mx-1 hidden sm:block"></div>

           <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleRestore} />
           <button 
             onClick={() => fileInputRef.current?.click()}
             className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 shadow-sm transition"
           >
             <Upload size={16} /> <span className="hidden sm:inline">Restore</span>
           </button>
           <button 
             onClick={handleBackup}
             className="flex items-center gap-2 px-3 py-2 bg-primary-600 text-white rounded-lg text-sm hover:bg-primary-700 shadow-sm transition font-medium"
           >
             <Download size={16} /> <span className="hidden sm:inline">Backup</span>
           </button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div 
          onClick={() => setShowRevenueDetails(true)}
          className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 flex items-center space-x-4 cursor-pointer hover:shadow-md transition group relative overflow-hidden"
        >
          <div className="absolute right-0 top-0 h-full w-1 bg-primary-500"></div>
          <div className="p-3 bg-primary-100 dark:bg-primary-900/30 rounded-full text-primary-600 dark:text-primary-400 group-hover:bg-primary-200 dark:group-hover:bg-primary-900/50 transition">
            <h3 className="font-bold text-xl">{currency}</h3>
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400 font-medium">Total Revenue</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{currency}{totalRevenue.toFixed(2)}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 flex items-center space-x-4">
          <div className="p-3 bg-blue-100 dark:bg-blue-900/30 rounded-full text-blue-600 dark:text-blue-400">
            <Package size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400 font-medium">Total {businessConfig?.labels.product}s</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{inventory.length}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 flex items-center space-x-4">
          <div className="p-3 bg-red-100 dark:bg-red-900/30 rounded-full text-red-600 dark:text-red-400">
            <AlertCircle size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400 font-medium">Attention Needed</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{lowStockItems.length + expiringSoon.length}</p>
          </div>
        </div>

        <div 
          onClick={() => setCurrentView(AppView.ORDERS)}
          className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 flex items-center space-x-4 cursor-pointer hover:shadow-md transition"
        >
          <div className="p-3 bg-purple-100 dark:bg-purple-900/30 rounded-full text-purple-600 dark:text-purple-400">
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400 font-medium">Active Orders</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{orders.filter(o => o.status === 'Pending').length}</p>
          </div>
        </div>
      </div>

      {/* Main Analysis Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Product Sales Analysis */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 flex flex-col h-[400px]">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-4 gap-4">
            <div>
                <h3 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
                    <Package size={20} className="text-indigo-600 dark:text-indigo-400"/> Product Sales
                </h3>
                <p className="text-xs text-gray-500 dark:text-gray-400">
                    Total Units Sold: <span className="font-bold text-primary-600 dark:text-primary-400">{totalItemsSold}</span>
                </p>
            </div>

            <div className="flex flex-wrap items-center gap-2 w-full sm:w-auto">
                <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg p-1 border border-gray-100 dark:border-gray-600">
                    <Filter size={14} className="text-gray-400 ml-1"/>
                    <select 
                        value={salesFilter} 
                        onChange={(e) => setSalesFilter(e.target.value)}
                        className="text-xs bg-transparent text-gray-700 dark:text-gray-200 outline-none font-medium cursor-pointer"
                    >
                        <option>Today</option>
                        <option>Yesterday</option>
                        <option>This Month</option>
                        <option>Last Month</option>
                        <option>Custom</option>
                    </select>
                </div>

                {salesFilter === 'Custom' && (
                    <input 
                        type="date" 
                        value={customDate}
                        onChange={(e) => setCustomDate(e.target.value)}
                        className="text-xs bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg px-2 py-1.5 outline-none text-gray-700 dark:text-gray-200"
                    />
                )}

                <button 
                    onClick={() => setShowCategoryModal(true)}
                    className="text-xs flex items-center gap-1 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 px-3 py-1.5 rounded-lg font-medium hover:bg-indigo-100 dark:hover:bg-indigo-900/50 transition border border-indigo-100 dark:border-indigo-800 ml-auto sm:ml-0"
                >
                    <Plus size={14}/> Add Category
                </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto pr-1">
            {productSalesList.length > 0 ? (
                <div className="relative overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="text-xs text-gray-500 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-700 sticky top-0">
                            <tr>
                                <th className="px-4 py-3 rounded-l-lg font-semibold">{businessConfig?.labels.product || 'Product'}</th>
                                <th className="px-4 py-3 text-right rounded-r-lg font-semibold">Qty Sold</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {productSalesList.map((item, index) => (
                                <tr key={index} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition duration-150">
                                    <td className="px-4 py-3 font-medium text-gray-800 dark:text-gray-200">
                                        {item.name}
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <span className="bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400 px-2 py-0.5 rounded-full font-bold text-xs border border-primary-100 dark:border-primary-900/50">
                                            {item.quantity}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            ) : (
                <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-gray-500 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-xl m-1">
                    <ShoppingBag size={32} className="mb-2 opacity-50"/>
                    <p className="text-sm">No sales found for this period</p>
                </div>
            )}
          </div>
        </div>

        {/* Recent Sales Trend */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700">
          <h3 className="text-lg font-bold mb-4 text-gray-800 dark:text-white flex items-center gap-2">
            <TrendingUp size={20} className="text-primary-600 dark:text-primary-400" /> Recent Sales Trend
          </h3>
          <div className="h-[320px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesData.length > 0 ? salesData : [{name: 'No Data', amount: 0}]}>
                <CartesianGrid strokeDasharray="3 3" stroke={chartGridColor} opacity={0.5} vertical={false}/>
                <XAxis dataKey="name" stroke={chartAxisColor} tick={{fill: chartAxisColor}} axisLine={false} tickLine={false} dy={10}/>
                <YAxis stroke={chartAxisColor} tick={{fill: chartAxisColor}} axisLine={false} tickLine={false}/>
                <Tooltip 
                    cursor={{fill: isDarkMode ? '#374151' : '#f3f4f6', opacity: 0.4}}
                    formatter={(value) => [`${currency}${value}`, 'Revenue']} 
                    contentStyle={tooltipStyle}
                />
                <Bar dataKey="amount" fill="var(--c-primary-600)" radius={[6, 6, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Alerts List */}
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
        <div className="p-4 bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700">
          <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2">
            <AlertCircle size={18} className="text-orange-500"/> Stock Alerts
          </h3>
        </div>
        <div className="p-4">
          {lowStockItems.length === 0 && expiringSoon.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-8 text-center">
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-2">
                    <Package className="text-green-600 dark:text-green-400" size={24}/>
                </div>
                <p className="text-gray-500 dark:text-gray-400 font-medium">Inventory looks healthy!</p>
            </div>
          ) : (
            <ul className="space-y-3">
              {lowStockItems.map(item => (
                <li 
                  key={item.id} 
                  onClick={() => handleAlertClick(item.name)}
                  className="flex items-center text-sm text-red-700 dark:text-red-300 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg cursor-pointer hover:bg-red-100 dark:hover:bg-red-900/30 transition border border-red-100 dark:border-red-900/30"
                >
                  <AlertCircle size={16} className="mr-2 shrink-0" />
                  <span className="flex-1">Low Stock: <b>{item.name}</b> (Only {item.quantity} left)</span>
                </li>
              ))}
              {expiringSoon.map(item => (
                <li 
                  key={item.id} 
                  onClick={() => handleAlertClick(item.name)}
                  className="flex items-center text-sm text-orange-700 dark:text-orange-300 bg-orange-50 dark:bg-orange-900/20 p-3 rounded-lg cursor-pointer hover:bg-orange-100 dark:hover:bg-orange-900/30 transition border border-orange-100 dark:border-orange-900/30"
                >
                  <AlertCircle size={16} className="mr-2 shrink-0" />
                  <span className="flex-1">Expiring Soon: <b>{item.name}</b> ({formatDate(item.expiryDate)})</span>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>

      {/* Revenue Details Modal */}
      {showRevenueDetails && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-xl max-w-4xl w-full max-h-[90vh] flex flex-col animate-in zoom-in duration-200 border border-gray-200 dark:border-gray-700">
            <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-700/50 rounded-t-xl">
              <h3 className="font-bold text-lg flex items-center gap-2 text-gray-800 dark:text-white">
                <TrendingUp size={20} className="text-primary-600 dark:text-primary-400"/> Revenue & Profit Analysis
              </h3>
              <button onClick={() => setShowRevenueDetails(false)} className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200">
                <X size={20} />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                <div className="p-4 bg-primary-50 dark:bg-primary-900/20 rounded-lg border border-primary-100 dark:border-primary-900/30">
                  <p className="text-sm text-primary-600 dark:text-primary-400 font-medium">Total Revenue</p>
                  <p className="text-2xl font-bold text-primary-800 dark:text-primary-200">{currency}{totalRevenue.toFixed(2)}</p>
                </div>
                <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-lg border border-green-100 dark:border-green-900/30">
                  <p className="text-sm text-green-600 dark:text-green-400 font-medium">Total Profit</p>
                  <p className="text-2xl font-bold text-green-800 dark:text-green-200">{currency}{totalProfit.toFixed(2)}</p>
                </div>
                <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-100 dark:border-blue-900/30">
                  <p className="text-sm text-blue-600 dark:text-blue-400 font-medium">Total Transactions</p>
                  <p className="text-2xl font-bold text-blue-800 dark:text-blue-200">{sales.length}</p>
                </div>
              </div>

              <div className="h-64 w-full mb-6">
                 <h4 className="font-semibold mb-2 text-gray-700 dark:text-gray-300">Daily Revenue vs Profit</h4>
                 <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={dailyData}>
                      <CartesianGrid strokeDasharray="3 3" stroke={chartGridColor} opacity={0.5} />
                      <XAxis dataKey="date" stroke={chartAxisColor} tick={{fill: chartAxisColor}} />
                      <YAxis stroke={chartAxisColor} tick={{fill: chartAxisColor}} />
                      <Tooltip contentStyle={tooltipStyle} />
                      <Legend />
                      <Line type="monotone" dataKey="revenue" stroke="var(--c-primary-600)" strokeWidth={2} name="Revenue" dot={{r: 4}} activeDot={{r: 6}} />
                      <Line type="monotone" dataKey="profit" stroke="#16a34a" strokeWidth={2} name="Profit" dot={{r: 4}} />
                    </LineChart>
                 </ResponsiveContainer>
              </div>

              <h4 className="font-bold text-gray-800 dark:text-white mb-4">Transaction History</h4>
              <div className="space-y-2">
                {sales.length === 0 ? (
                    <p className="text-gray-500 dark:text-gray-400 text-center">No sales recorded yet.</p>
                ) : (
                    sales.map(sale => (
                        <div key={sale.id} className="border border-gray-200 dark:border-gray-700 rounded-lg p-3 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition flex justify-between items-center bg-white dark:bg-gray-800">
                            <div>
                                <p className="font-bold text-sm text-gray-800 dark:text-gray-200">{sale.customerName}</p>
                                <p className="text-xs text-gray-500 dark:text-gray-400">{new Date(sale.date).toLocaleString()} • {sale.id}</p>
                            </div>
                            <div className="text-right">
                                <span className="block font-bold text-primary-600 dark:text-primary-400">{currency}{sale.totalAmount.toFixed(2)}</span>
                                <span className="text-xs text-green-600 dark:text-green-400">Profit: {currency}{(sale.profit || 0).toFixed(2)}</span>
                            </div>
                        </div>
                    ))
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add Category Modal */}
      {showCategoryModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-xl max-w-sm w-full animate-in zoom-in duration-200 border border-gray-200 dark:border-gray-700 p-6">
             <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-lg text-gray-800 dark:text-white">Add New Category</h3>
                <button onClick={() => setShowCategoryModal(false)}><X size={20} className="text-gray-400"/></button>
             </div>
             <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">Create a new category to organize your inventory better.</p>
             <input 
                autoFocus
                className="w-full p-3 border border-gray-300 dark:border-gray-600 rounded-lg mb-4 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none"
                placeholder="Category Name (e.g., Dental)"
                value={newCategory}
                onChange={(e) => setNewCategory(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddCategory()}
             />
             <div className="flex justify-end gap-2">
                <button onClick={() => setShowCategoryModal(false)} className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg font-medium">Cancel</button>
                <button onClick={handleAddCategory} className="px-4 py-2 bg-primary-600 text-white rounded-lg font-medium hover:bg-primary-700">Add Category</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { Truck, CheckCircle, Clock, XCircle, Plus, X, Search, ChevronDown, Package, Calendar, DollarSign } from 'lucide-react';
import { OrderItem, Medicine } from '../types';

const Orders: React.FC = () => {
  const { orders, inventory, addOrder, receiveOrder, formatDate, businessConfig } = usePharmacy();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isReceiveModalOpen, setIsReceiveModalOpen] = useState(false);
  const [activeOrder, setActiveOrder] = useState<string | null>(null);
  const [receiveItems, setReceiveItems] = useState<Partial<Medicine>[]>([]);

  // Create Order State
  const [wholesalerName, setWholesalerName] = useState('');
  const [orderItems, setOrderItems] = useState<OrderItem[]>([]);
  const [qty, setQty] = useState(1);
  const [itemSearch, setItemSearch] = useState('');
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);

  // Filter unique medicine names for the dropdown to avoid duplicates in list
  const uniqueMedicines = Array.from(new Set(inventory.map(m => m.name)))
    .map(name => inventory.find(m => m.name === name)!);

  const filteredMedicines = uniqueMedicines.filter(m => 
    m.name.toLowerCase().includes(itemSearch.toLowerCase())
  );

  const handleSelectMedicine = (name: string, id: string) => {
    setItemSearch(name);
    setIsDropdownOpen(false);
  };

  const handleAddItem = () => {
    if (!itemSearch) return;

    // Find existing ID if matches, otherwise just use name
    const existing = inventory.find(i => i.name.toLowerCase() === itemSearch.toLowerCase());
    const id = existing ? existing.id : `TEMP-${Date.now()}`;

    setOrderItems(prev => {
        const existItem = prev.find(p => p.name.toLowerCase() === itemSearch.toLowerCase());
        if (existItem) {
            return prev.map(p => p.name.toLowerCase() === itemSearch.toLowerCase() ? {...p, quantity: p.quantity + qty} : p);
        }
        return [...prev, { medicineId: id, name: itemSearch, quantity: qty }];
    });
    setQty(1);
    setItemSearch('');
  };

  const handleCreateOrder = () => {
    if (!wholesalerName || orderItems.length === 0) return;

    addOrder({
        id: `ORD-${Date.now()}`,
        wholesalerName,
        date: new Date().toISOString().split('T')[0],
        status: 'Pending',
        items: orderItems
    });

    setIsModalOpen(false);
    setWholesalerName('');
    setOrderItems([]);
    setItemSearch('');
  };

  const openReceiveModal = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;

    setActiveOrder(orderId);
    // Initialize receive items based on order items
    // One entry per item ordered, requesting batch info
    const initItems: Partial<Medicine>[] = order.items.map(item => {
        // Try to pre-fill info if product exists
        const existing = inventory.find(i => i.name === item.name);
        return {
            name: item.name,
            quantity: item.quantity,
            batchNumber: '',
            expiryDate: '',
            purchasePrice: existing?.purchasePrice || 0,
            mrp: existing?.mrp || 0,
            category: existing?.category || 'General',
            barcode: existing?.barcode || ''
        }
    });
    setReceiveItems(initItems);
    setIsReceiveModalOpen(true);
  };

  const handleReceiveItemChange = (index: number, field: keyof Medicine, value: any) => {
    const newItems = [...receiveItems];
    newItems[index] = { ...newItems[index], [field]: value };
    setReceiveItems(newItems);
  };

  const handleConfirmReceive = () => {
    if (!activeOrder) return;

    // Validate inputs based on business config
    const needsBatch = businessConfig?.fields.showBatch;
    const needsExpiry = businessConfig?.fields.showExpiry;

    if (receiveItems.some(i => (needsBatch && !i.batchNumber) || (needsExpiry && !i.expiryDate) || !i.purchasePrice || !i.mrp)) {
        alert("Please fill in all required details (Batch, Expiry, Prices) for the received items.");
        return;
    }

    // Convert to full Medicine objects
    const finalItems: Medicine[] = receiveItems.map((item, idx) => ({
        id: Date.now().toString() + idx, // Generate new ID
        name: item.name!,
        batchNumber: item.batchNumber || '',
        expiryDate: item.expiryDate || new Date().toISOString().split('T')[0],
        quantity: item.quantity!,
        purchasePrice: Number(item.purchasePrice),
        mrp: Number(item.mrp),
        barcode: item.barcode || `8${Date.now().toString().slice(-12) + idx}`,
        category: item.category || 'General'
    }));

    receiveOrder(activeOrder, finalItems);
    setIsReceiveModalOpen(false);
    setActiveOrder(null);
  };

  const inputClass = "w-full px-4 py-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-800 dark:text-gray-200 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all shadow-sm text-sm font-medium";

  return (
    <div className="p-4 h-full relative bg-gray-50/50 dark:bg-gray-900/50">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
            <Truck className="text-primary-600 dark:text-primary-400"/> Supplier Orders
        </h2>
        <button 
            onClick={() => setIsModalOpen(true)}
            className="hidden md:flex items-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 text-white px-5 py-2.5 rounded-xl hover:from-primary-700 hover:to-primary-600 transition shadow-md font-medium"
        >
            <Plus size={18} /> New Order
        </button>
      </div>

      <div className="grid gap-4 pb-20">
        {orders.map(order => (
          <div key={order.id} className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 flex flex-col md:flex-row justify-between items-start md:items-center gap-6 hover:shadow-md transition">
            <div className="flex items-start gap-4 flex-1">
              <div className={`p-4 rounded-xl text-white ${order.status === 'Pending' ? 'bg-orange-400' : order.status === 'Completed' ? 'bg-green-500' : 'bg-red-500'}`}>
                <Package size={24} />
              </div>
              <div>
                <h3 className="font-bold text-lg text-gray-800 dark:text-gray-100">{order.wholesalerName}</h3>
                <p className="text-xs text-gray-500 dark:text-gray-400 font-medium bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded w-fit mt-1">ID: {order.id}</p>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-1"><Calendar size={14}/> {formatDate(order.date)}</p>

                <div className="mt-3 flex flex-wrap gap-2">
                    {order.items.slice(0, 3).map((item, idx) => (
                        <span key={idx} className="text-xs bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-700 px-2 py-1 rounded text-gray-700 dark:text-gray-300">
                            {item.name} <span className="font-bold text-primary-600 dark:text-primary-400">x{item.quantity}</span>
                        </span>
                    ))}
                    {order.items.length > 3 && <span className="text-xs text-gray-400 dark:text-gray-500 self-center">+{order.items.length - 3} more</span>}
                </div>
              </div>
            </div>

            <div className="flex items-center gap-4 w-full md:w-auto justify-end border-t border-gray-100 dark:border-gray-700 md:border-t-0 pt-4 md:pt-0 mt-2 md:mt-0">
                {order.status === 'Pending' && (
                    <div className="flex flex-col items-end gap-2">
                         <span className="flex items-center gap-1 bg-orange-50 dark:bg-orange-900/20 text-orange-700 dark:text-orange-400 border border-orange-100 dark:border-orange-900/30 px-3 py-1 rounded-full text-sm font-bold">
                            <Clock size={16} /> Pending
                        </span>
                        <button 
                            onClick={() => openReceiveModal(order.id)}
                            className="bg-primary-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-primary-700 shadow-sm transition"
                        >
                            Receive Stock
                        </button>
                    </div>
                )}
                {order.status === 'Completed' && (
                    <span className="flex items-center gap-1 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 border border-green-100 dark:border-green-900/30 px-4 py-1.5 rounded-full text-sm font-bold">
                        <CheckCircle size={16} /> Received
                    </span>
                )}
                 {order.status === 'Cancelled' && (
                    <span className="flex items-center gap-1 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 border border-red-100 dark:border-red-900/30 px-4 py-1.5 rounded-full text-sm font-bold">
                        <XCircle size={16} /> Cancelled
                    </span>
                )}
            </div>
          </div>
        ))}
      </div>

      {/* Mobile FAB */}
      <div className="md:hidden fixed bottom-24 right-6 z-10">
        <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-primary-600 text-white p-4 rounded-full shadow-lg hover:bg-primary-700 transition transform hover:scale-105"
        >
           <Plus size={24} />
        </button>
      </div>

      {/* Create Order Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">
                <div className="p-5 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-gray-700/50">
                    <h3 className="font-bold text-lg text-gray-800 dark:text-white">New Supplier Order</h3>
                    <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 transition">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto space-y-5">
                    <div>
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1.5">Supplier / Wholesaler Name</label>
                        <input 
                            value={wholesalerName}
                            onChange={(e) => setWholesalerName(e.target.value)}
                            className={inputClass}
                            placeholder="e.g. Global Supplies" 
                        />
                    </div>

                    <div className="border-t border-gray-100 dark:border-gray-700 pt-5">
                        <h4 className="font-bold text-sm text-gray-700 dark:text-gray-300 mb-3 flex items-center gap-2"><Package size={16}/> Order Items</h4>
                        <div className="flex gap-2 mb-2 items-start">
                            <div className="flex-1 relative">
                                <div className="relative">
                                    <Search size={18} className="absolute left-3 top-3.5 text-gray-400"/>
                                    <input 
                                        type="text"
                                        value={itemSearch}
                                        onChange={(e) => {
                                            setItemSearch(e.target.value);
                                            setIsDropdownOpen(true);
                                        }}
                                        onFocus={() => setIsDropdownOpen(true)}
                                        className={`${inputClass} pl-10`}
                                        placeholder={`Search ${businessConfig?.labels.product.toLowerCase()}...`}
                                    />
                                    {isDropdownOpen && <ChevronDown size={16} className="absolute right-3 top-3.5 text-gray-400"/>}
                                </div>
                                {isDropdownOpen && filteredMedicines.length > 0 && (
                                    <div className="absolute top-full left-0 w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 mt-2 rounded-xl shadow-xl max-h-48 overflow-y-auto z-50">
                                        {filteredMedicines.map(med => (
                                            <div 
                                                key={med.id}
                                                onClick={() => handleSelectMedicine(med.name, med.id)}
                                                className="p-3 hover:bg-primary-50 dark:hover:bg-primary-900/20 cursor-pointer text-sm font-medium text-gray-700 dark:text-gray-200 border-b border-gray-50 dark:border-gray-700 last:border-0"
                                            >
                                                {med.name}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                            <input 
                                type="number" 
                                min="1" 
                                value={qty}
                                onChange={(e) => setQty(parseInt(e.target.value))}
                                className="w-20 px-2 py-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-sm text-center font-bold focus:outline-none focus:ring-2 focus:ring-primary-500 text-gray-800 dark:text-white"
                            />
                            <button 
                                onClick={handleAddItem}
                                className="bg-primary-600 text-white p-3 rounded-xl hover:bg-primary-700 transition shadow-md"
                            >
                                <Plus size={20}/>
                            </button>
                        </div>

                        {orderItems.length > 0 && (
                            <div className="bg-gray-50 dark:bg-gray-700/30 p-3 rounded-xl border border-gray-200 dark:border-gray-700 space-y-2 mt-4 max-h-40 overflow-y-auto">
                                {orderItems.map((item, idx) => (
                                    <div key={idx} className="flex justify-between items-center text-sm bg-white dark:bg-gray-800 p-2 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700">
                                        <span className="font-medium text-gray-700 dark:text-gray-200">{item.name}</span>
                                        <span className="font-bold text-primary-600 dark:text-primary-400 bg-primary-50 dark:bg-primary-900/20 px-2 py-0.5 rounded">x{item.quantity}</span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-5 border-t border-gray-100 dark:border-gray-700 flex justify-end gap-3 bg-gray-50/50 dark:bg-gray-700/50">
                    <button onClick={() => setIsModalOpen(false)} className="px-5 py-2.5 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-xl font-medium transition">Cancel</button>
                    <button 
                        onClick={handleCreateOrder}
                        disabled={!wholesalerName || orderItems.length === 0}
                        className={`px-6 py-2.5 text-white rounded-xl font-medium shadow-lg transition ${!wholesalerName || orderItems.length === 0 ? 'bg-gray-400 dark:bg-gray-600 cursor-not-allowed' : 'bg-primary-600 hover:bg-primary-700'}`}
                    >
                        Place Order
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Receive Order Modal */}
      {isReceiveModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">
                <div className="p-5 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-gray-700/50">
                    <h3 className="font-bold text-xl text-gray-800 dark:text-white">Receive Stock</h3>
                    <button onClick={() => setIsReceiveModalOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto bg-gray-50/30 dark:bg-gray-900/30">
                    <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-900/30 p-4 rounded-xl mb-6 flex gap-3">
                        <CheckCircle className="text-blue-500 dark:text-blue-400 shrink-0" size={24} />
                        <div>
                            <p className="text-sm font-bold text-blue-800 dark:text-blue-200">Verify Shipment</p>
                            <p className="text-xs text-blue-600 dark:text-blue-400 mt-1">
                                Enter the {businessConfig?.fields.showBatch ? 'Batch Number, ' : ''} {businessConfig?.fields.showExpiry ? 'Expiry Date, ' : ''} and Prices for each item.
                            </p>
                        </div>
                    </div>

                    <div className="space-y-4">
                        {receiveItems.map((item, idx) => (
                            <div key={idx} className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 p-5 rounded-2xl shadow-sm">
                                <div className="flex justify-between items-center mb-4 pb-2 border-b border-gray-100 dark:border-gray-700">
                                    <div className="font-bold text-lg text-gray-800 dark:text-gray-100">{item.name}</div>
                                    <div className="bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-400 px-3 py-1 rounded-lg text-sm font-bold border border-primary-100 dark:border-primary-900/30">Qty: {item.quantity}</div>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                    {businessConfig?.fields.showBatch && (
                                        <div>
                                            <label className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Batch #</label>
                                            <input 
                                                value={item.batchNumber}
                                                onChange={(e) => handleReceiveItemChange(idx, 'batchNumber', e.target.value)}
                                                className={inputClass}
                                                placeholder="Batch ID"
                                            />
                                        </div>
                                    )}
                                    {businessConfig?.fields.showExpiry && (
                                        <div>
                                            <label className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Expiry</label>
                                            <input 
                                                type="date"
                                                value={item.expiryDate}
                                                onChange={(e) => handleReceiveItemChange(idx, 'expiryDate', e.target.value)}
                                                className={inputClass}
                                            />
                                        </div>
                                    )}
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Buy Price (₹)</label>
                                        <input 
                                            type="number"
                                            value={item.purchasePrice || ''}
                                            onChange={(e) => handleReceiveItemChange(idx, 'purchasePrice', parseFloat(e.target.value))}
                                            className={inputClass}
                                            placeholder="0.00"
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">MRP (₹)</label>
                                        <input 
                                            type="number"
                                            value={item.mrp || ''}
                                            onChange={(e) => handleReceiveItemChange(idx, 'mrp', parseFloat(e.target.value))}
                                            className={inputClass}
                                            placeholder="0.00"
                                        />
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="p-5 border-t border-gray-100 dark:border-gray-700 flex justify-end gap-3 bg-gray-50/50 dark:bg-gray-700/50">
                    <button onClick={() => setIsReceiveModalOpen(false)} className="px-5 py-2.5 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-xl font-medium transition">Cancel</button>
                    <button 
                        onClick={handleConfirmReceive}
                        className="px-6 py-2.5 text-white bg-green-600 hover:bg-green-700 rounded-xl font-medium shadow-lg shadow-green-600/20 transition flex items-center gap-2"
                    >
                        <CheckCircle size={18} /> Confirm Reception
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Orders;

