import React, { useState } from 'react';
import { Upload, Sparkles, AlertTriangle, FileText, CheckCircle, Lock } from 'lucide-react';
import { analyzePrescription } from '../services/geminiService';
import { PrescriptionAnalysis } from '../types';
import { usePharmacy } from '../services/context/PharmacyContext';

const PrescriptionScanner: React.FC = () => {
  const { isPaid } = usePharmacy();
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<PrescriptionAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
      setResult(null);
      setError(null);
    }
  };

  const handleAnalyze = async () => {
    if (!file) return;
    setIsAnalyzing(true);
    setError(null);

    try {
      const data = await analyzePrescription(file);
      setResult(data);
    } catch (err) {
      setError("Failed to analyze image. Please try again with a clearer image.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isPaid) {
      return (
        <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-gray-50 rounded-2xl border border-gray-200 m-4 relative overflow-hidden">
             <div className="absolute inset-0 bg-gradient-to-br from-primary-500/5 to-blue-500/5"></div>
             <div className="bg-white p-4 rounded-full shadow-lg mb-6 z-10">
                <Lock size={48} className="text-gray-400" />
            </div>
            <h2 className="text-3xl font-bold text-gray-800 mb-2 z-10">AI Prescription Scanner</h2>
            <p className="text-gray-500 max-w-md mb-8 z-10">
                Upgrade to Pro to unlock advanced AI image analysis. Automatically digitize prescriptions and handwritten notes instantly.
            </p>
            <div className="flex gap-4 z-10 opacity-75 grayscale">
                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center w-32">
                    <FileText className="text-primary-500 mb-2" />
                    <span className="text-xs font-bold text-gray-600">Scan Rx</span>
                 </div>
                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center w-32">
                    <Sparkles className="text-blue-500 mb-2" />
                    <span className="text-xs font-bold text-gray-600">AI Extract</span>
                 </div>
            </div>
            <p className="mt-8 text-sm text-gray-400 z-10">Premium Feature</p>
        </div>
      );
  }

  return (
    <div className="p-4 h-full flex flex-col md:flex-row gap-6">
      {/* Upload Section */}
      <div className="w-full md:w-1/2 flex flex-col gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <Upload size={24} className="text-primary-600"/> Upload Prescription
          </h2>

          <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 flex flex-col items-center justify-center text-center bg-gray-50 h-64 relative">
            {preview ? (
              <img src={preview} alt="Preview" className="max-h-full max-w-full object-contain rounded" />
            ) : (
              <div className="text-gray-400">
                <FileText size={48} className="mx-auto mb-2" />
                <p>Click to upload or drag image here</p>
              </div>
            )}
            <input 
              type="file" 
              accept="image/*"
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
          </div>

          <button
            onClick={handleAnalyze}
            disabled={!file || isAnalyzing}
            className={`w-full mt-6 py-3 rounded-lg font-bold text-white flex justify-center items-center gap-2 transition ${!file ? 'bg-gray-300 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-primary-600 hover:from-blue-700 hover:to-primary-700 shadow-md'}`}
          >
            {isAnalyzing ? (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                Analyzing with Gemini...
              </>
            ) : (
              <>
                <Sparkles size={20} /> Analyze Prescription
              </>
            )}
          </button>

          <p className="text-xs text-gray-500 mt-4 text-center">
            Supported formats: JPG, PNG. Ensure handwriting is legible for best AI results.
          </p>
        </div>
      </div>

      {/* Results Section */}
      <div className="w-full md:w-1/2">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full flex flex-col">
          <h2 className="text-xl font-bold mb-4 text-gray-800">Analysis Results</h2>

          {error && (
            <div className="bg-red-50 text-red-700 p-4 rounded-lg flex items-center gap-2">
              <AlertTriangle size={20} />
              {error}
            </div>
          )}

          {!result && !error && !isAnalyzing && (
            <div className="flex-1 flex flex-col items-center justify-center text-gray-400 text-center p-8">
              <Sparkles size={48} className="mb-4 text-gray-200" />
              <p>Upload a prescription and let Gemini AI extract medicine details for you.</p>
            </div>
          )}

          {result && (
            <div className="flex-1 overflow-auto space-y-4">
              {/* Summary Note */}
              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
                <h3 className="font-semibold text-blue-800 text-sm mb-1">AI Note</h3>
                <p className="text-sm text-blue-700">{result.notes || "Analysis complete."}</p>
              </div>

              {/* Medicines List */}
              <div className="space-y-3">
                <h3 className="font-semibold text-gray-700">Detected Medicines</h3>
                {result.medicines && result.medicines.length > 0 ? (
                  result.medicines.map((med, idx) => (
                    <div key={idx} className="border border-gray-200 rounded-lg p-3 hover:shadow-md transition bg-gray-50">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-primary-700">{med.name}</h4>
                        <span className="bg-primary-100 text-primary-800 text-xs px-2 py-1 rounded-full">{med.dosage}</span>
                      </div>
                      <p className="text-sm text-gray-600 mt-2 flex items-center gap-1">
                        <CheckCircle size={14} className="text-primary-500"/> {med.instructions}
                      </p>
                    </div>
                  ))
                ) : (
                  <p className="text-gray-500 italic">No specific medicines detected.</p>
                )}
              </div>

              <div className="mt-4 pt-4 border-t">
                 <button className="w-full py-2 border border-primary-600 text-primary-600 rounded-lg font-medium hover:bg-primary-50">
                    Add All to Cart (Demo)
                 </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PrescriptionScanner;

import React, { useState } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { BusinessType, BusinessConfig, AppTheme } from '../types';
import { Store, ShoppingBag, Utensils, Coffee, Pill, ChevronDown, Check, ArrowRight, Sun, Moon, Settings, Layers, List, Palette } from 'lucide-react';

const Onboarding: React.FC = () => {
  const { updateBusinessConfig, initializeBusinessData, isDarkMode, toggleDarkMode, theme, setTheme } = usePharmacy();
  const [step, setStep] = useState(1);
  const [selectedType, setSelectedType] = useState<BusinessType | null>(null);
  const [details, setDetails] = useState({
    name: '',
    address: '',
    contact: '',
    currency: '₹',
    defaultGst: 0
  });

  // Custom Field Configuration State
  const [configData, setConfigData] = useState({
    // Modules
    enableInventory: true,
    enablePOS: true,
    enableOrders: true,
    enableScanner: false,
    enableInsights: true,
    enableSalesHistory: true,
    // Fields
    showBatch: true,
    showExpiry: true,
    showDoctor: true,
    // Features
    enableKitchen: false
  });

  const businessTypes = [
    { id: 'PHARMACY', label: 'Pharmacy', icon: Pill, desc: 'Includes Doctor details, Prescriptions, Batch & Expiry tracking.' },
    { id: 'RETAIL', label: 'Clothing / Retail', icon: ShoppingBag, desc: 'Simple inventory, Barcode support, No expiration dates.' },
    { id: 'RESTAURANT', label: 'Restaurant', icon: Utensils, desc: 'Manage Dishes, Tables, Orders. Kitchen Display support.' },
    { id: 'GROCERY', label: 'Grocery Store', icon: Store, desc: 'Batch tracking, Expiry dates, Fast barcode billing.' },
    { id: 'CAFE', label: 'Cafe', icon: Coffee, desc: 'Quick service, Simple menu management.' },
  ];

  const applyPresets = (type: BusinessType) => {
    let defaults = {
        enableInventory: true,
        enablePOS: true,
        enableOrders: true,
        enableScanner: false,
        enableInsights: true,
        enableSalesHistory: true,
        showBatch: true,
        showExpiry: true,
        showDoctor: true,
        enableKitchen: false
    };

    let defaultGst = 0;

    switch (type) {
        case 'PHARMACY':
            defaults.enableScanner = true;
            defaultGst = 12;
            break;
        case 'GROCERY':
            defaults.showDoctor = false;
            defaultGst = 5;
            break;
        case 'RESTAURANT':
        case 'CAFE':
            defaults.showBatch = false;
            defaults.showExpiry = false;
            defaults.showDoctor = false;
            defaults.enableKitchen = true;
            defaultGst = 5;
            break;
        case 'RETAIL':
            defaults.showBatch = false;
            defaults.showExpiry = false;
            defaults.showDoctor = false;
            defaultGst = 12;
            break;
    }
    setConfigData(defaults);
    setDetails(prev => ({...prev, defaultGst}));
  };

  const handleFinish = () => {
    if (!selectedType) return;

    let config: BusinessConfig = {
      type: selectedType as BusinessType,
      details: details,
      labels: {
        product: 'Product',
        customer: 'Customer'
      },
      modules: {
        enableInventory: configData.enableInventory,
        enablePOS: configData.enablePOS,
        enableOrders: configData.enableOrders,
        enableScanner: configData.enableScanner,
        enableInsights: configData.enableInsights,
        enableSalesHistory: configData.enableSalesHistory,
      },
      features: {
        enableKitchenDisplay: configData.enableKitchen,
      },
      fields: {
        showBatch: configData.showBatch,
        showExpiry: configData.showExpiry,
        showDoctor: configData.showDoctor,
      }
    };

    // Set Labels
    if(selectedType === 'PHARMACY') { config.labels.product = 'Medicine'; config.labels.customer = 'Patient'; }
    if(selectedType === 'RESTAURANT' || selectedType === 'CAFE') { config.labels.product = 'Dish'; config.labels.customer = 'Guest'; }
    if(selectedType === 'GROCERY') { config.labels.product = 'Item'; }

    initializeBusinessData(selectedType);
    updateBusinessConfig(config);
  };

  const inputClass = "w-full px-4 py-3 bg-white border border-gray-200 rounded-xl text-gray-800 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all shadow-sm text-sm font-medium dark:bg-gray-800 dark:border-gray-700 dark:text-white";

  const ThemeOption = ({ t, color, label }: { t: AppTheme, color: string, label: string }) => (
    <button 
      onClick={() => setTheme(t)}
      className={`p-3 rounded-xl border-2 flex flex-col items-center gap-2 transition ${theme === t ? 'border-primary-600 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700 hover:border-gray-300'}`}
    >
      <div 
        className="w-10 h-10 rounded-full shadow-sm" 
        style={t === 'gradient' ? { background: 'linear-gradient(135deg, #2dd4bf, #3b82f6, #8b5cf6)' } : { backgroundColor: color }}
      ></div>
      <span className="text-xs font-bold text-gray-700 dark:text-gray-300">{label}</span>
    </button>
  );

  return (
