            <p className="opacity-90">Let's set up your store in seconds.</p>
        </div>

        <div className="p-8">
            {step === 1 && (
                <div className="space-y-6">
                    <h2 className="text-xl font-bold text-gray-800 dark:text-white">What kind of business do you run?</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {businessTypes.map((b) => {
                            const Icon = b.icon;
                            return (
                                <button
                                    key={b.id}
                                    onClick={() => {
                                        setSelectedType(b.id as BusinessType);
                                        applyPresets(b.id as BusinessType);
                                    }}
                                    className={`p-4 rounded-xl border-2 text-left transition flex items-start gap-4 ${selectedType === b.id ? 'border-primary-600 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700 hover:border-primary-200 dark:hover:border-primary-800'}`}
