                                    <div className={`p-3 rounded-full ${selectedType === b.id ? 'bg-primary-600 text-white' : 'bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-300'}`}>
                                        <Icon size={24} />
                                    </div>
                                    <div>
                                        <h3 className={`font-bold ${selectedType === b.id ? 'text-primary-800 dark:text-primary-400' : 'text-gray-800 dark:text-white'}`}>{b.label}</h3>
