                                    { key: 'enableSalesHistory', label: 'Sales History' },
                                    { key: 'enableScanner', label: 'AI Scanner' },
                                    { key: 'enableInsights', label: 'AI Business Insights' },
                                ].map((item) => (
                                    <div 
                                        key={item.key}
                                        onClick={() => setConfigData(prev => ({...prev, [item.key]: !prev[item.key as keyof typeof configData]}))}
                                        className={`flex items-center justify-between p-3 rounded-lg border cursor-pointer transition ${configData[item.key as keyof typeof configData] ? 'border-primary-500 bg-white dark:bg-gray-800 shadow-sm' : 'border-transparent bg-transparent opacity-70'}`}
                                    >
                                        <span className="text-sm font-medium text-gray-800 dark:text-gray-200">{item.label}</span>
                                        <div className={`w-5 h-5 rounded flex items-center justify-center border ${configData[item.key as keyof typeof configData] ? 'bg-primary-500 border-primary-500 text-white' : 'border-gray-400 text-transparent'}`}>
                                            <Check size={14} />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="bg-gray-50 dark:bg-gray-700/50 p-4 rounded-xl">
                            <h4 className="font-bold text-gray-700 dark:text-gray-200 mb-3 flex items-center gap-2"><List size={18}/> Data Fields</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                {[
                                    { key: 'showBatch', label: 'Batch Tracking' },
                                    { key: 'showExpiry', label: 'Expiry Dates' },
                                    { key: 'showDoctor', label: 'Doctor / Ref Field' },
                                    { key: 'enableKitchen', label: 'Kitchen Display' },
                                ].map((item) => (
                                    <div 
                                        key={item.key}
                                        onClick={() => setConfigData(prev => ({...prev, [item.key]: !prev[item.key as keyof typeof configData]}))}
                                        className={`flex items-center justify-between p-3 rounded-lg border cursor-pointer transition ${configData[item.key as keyof typeof configData] ? 'border-primary-500 bg-white dark:bg-gray-800 shadow-sm' : 'border-transparent bg-transparent opacity-70'}`}
                                    >
                                        <span className="text-sm font-medium text-gray-800 dark:text-gray-200">{item.label}</span>
                                        <div className={`w-5 h-5 rounded flex items-center justify-center border ${configData[item.key as keyof typeof configData] ? 'bg-primary-500 border-primary-500 text-white' : 'border-gray-400 text-transparent'}`}>
                                            <Check size={14} />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-between pt-4">
                        <button 
                            onClick={() => setStep(3)}
                            className="text-gray-500 dark:text-gray-400 hover:text-gray-800 dark:hover:text-white font-medium px-4"
                        >
                            Back
                        </button>
                        <button 
                            onClick={handleFinish}
                            className="px-8 py-3 rounded-xl font-bold text-white transition bg-primary-600 hover:bg-primary-700 shadow-lg"
                        >
                            Launch App
                        </button>
                    </div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

