        <div className="flex gap-4 z-10">
             <div className="bg-white dark:bg-gray-700 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-600 flex flex-col items-center w-32">
                <TrendingUp className="text-primary-500 dark:text-primary-400 mb-2" />
                <span className="text-xs font-bold text-gray-600 dark:text-gray-300">Sales Forecast</span>
             </div>
             <div className="bg-white dark:bg-gray-700 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-600 flex flex-col items-center w-32">
                <AlertTriangle className="text-orange-500 dark:text-orange-400 mb-2" />
