                <Sparkles className="text-purple-600 dark:text-purple-400" /> AI Business Analyst
            </h2>
            <p className="text-gray-500 dark:text-gray-400 text-sm">Powered by Gemini Pro</p>
        </div>
        {!analysis && !isLoading && (
            <button 
                onClick={handleAnalyze}
                className="bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:shadow-xl transition transform hover:scale-105 flex items-center gap-2"
            >
                <Sparkles size={18} /> Generate Report
            </button>
        )}
      </div>

      {isLoading && (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-500 dark:text-gray-400">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mb-4"></div>
            <p>Analyzing {sales.length} sales and {inventory.length} inventory items...</p>
