import React, { useState, useEffect } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { BusinessConfig, AppTheme } from '../types';
import { Settings, Save, Check, Layers, List, Palette } from 'lucide-react';

const Configuration: React.FC = () => {
  const { businessConfig, updateBusinessConfig, theme, setTheme } = usePharmacy();
  const [formData, setFormData] = useState<BusinessConfig | null>(null);
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    if (businessConfig) {
      setFormData(JSON.parse(JSON.stringify(businessConfig)));
    }
  }, [businessConfig]);

  if (!formData) return null;

  const handleDetailChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData(prev => prev ? ({
      ...prev,
      details: { ...prev.details, [e.target.name]: e.target.name === 'defaultGst' ? parseFloat(e.target.value) : e.target.value }
    }) : null);
    setIsSaved(false);
  };

  const handleModuleToggle = (key: keyof BusinessConfig['modules']) => {
    setFormData(prev => prev ? ({
      ...prev,
      modules: { ...prev.modules, [key]: !prev.modules[key] }
    }) : null);
    setIsSaved(false);
  };

  const handleFieldToggle = (key: keyof BusinessConfig['fields']) => {
    setFormData(prev => prev ? ({
      ...prev,
      fields: { ...prev.fields, [key]: !prev.fields[key] }
    }) : null);
    setIsSaved(false);
  };

  const handleSave = () => {
    if (formData) {
      updateBusinessConfig(formData);
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 2000);
    }
  };

  const inputClass = "w-full px-4 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-2 focus:ring-primary-500 transition shadow-sm text-sm";
  const labelClass = "block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1.5 ml-1";

  const ModuleToggle = ({ k, label, desc }: { k: keyof BusinessConfig['modules'], label: string, desc: string }) => (
    <div 
        onClick={() => handleModuleToggle(k)}
        className={`flex items-center justify-between p-4 rounded-xl border-2 cursor-pointer transition ${formData.modules[k] ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700'}`}
    >
        <div>
            <h4 className="font-bold text-gray-800 dark:text-white text-sm">{label}</h4>
            <p className="text-xs text-gray-500 dark:text-gray-400">{desc}</p>
        </div>
        <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.modules[k] ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
            {formData.modules[k] && <Check size={14} />}
        </div>
    </div>
  );

  const ThemeButton = ({ t, color }: { t: AppTheme, color: string }) => (
    <button 
      onClick={() => setTheme(t)}
      className={`w-12 h-12 rounded-full border-2 flex items-center justify-center transition shadow-sm ${theme === t ? 'border-gray-800 dark:border-white scale-110' : 'border-transparent hover:scale-105'}`}
      style={t === 'gradient' ? { background: 'linear-gradient(135deg, #2dd4bf, #3b82f6, #8b5cf6)' } : { backgroundColor: color }}
      title={t.charAt(0).toUpperCase() + t.slice(1)}
    >
      {theme === t && <span className="w-3 h-3 bg-white rounded-full"></span>}
    </button>
  );

  return (
    <div className="p-4 h-full bg-gray-50/50 dark:bg-gray-900/50 overflow-y-auto">
      <div className="max-w-4xl mx-auto pb-20">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
            <Settings className="text-primary-600 dark:text-primary-400" /> Store Configuration
          </h2>
          <button 
            onClick={handleSave}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold text-white shadow-lg transition transform active:scale-95 ${isSaved ? 'bg-green-600' : 'bg-primary-600 hover:bg-primary-700'}`}
          >
            {isSaved ? <Check size={18} /> : <Save size={18} />}
            {isSaved ? 'Saved!' : 'Save Changes'}
          </button>
        </div>

        <div className="grid gap-6">
          {/* Store Details Section */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
            <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 border-b border-gray-100 dark:border-gray-700 pb-2">Business Profile</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <div>
                  <label className={labelClass}>Business Name</label>
                  <input name="name" value={formData.details.name} onChange={handleDetailChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Currency Symbol</label>
                  <select name="currency" value={formData.details.currency} onChange={handleDetailChange} className={inputClass}>
                    <option value="₹">₹ (INR)</option>
                    <option value="$">$ (USD)</option>
                    <option value="€">€ (EUR)</option>
                    <option value="£">£ (GBP)</option>
                    <option value="AED">AED</option>
                  </select>
               </div>
               <div className="md:col-span-2">
                  <label className={labelClass}>Address</label>
                  <input name="address" value={formData.details.address} onChange={handleDetailChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Contact Number</label>
                  <input name="contact" value={formData.details.contact} onChange={handleDetailChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>System Default GST %</label>
                  <input type="number" name="defaultGst" value={formData.details.defaultGst} onChange={handleDetailChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Business Type (Read Only)</label>
                  <input disabled value={formData.type} className={`${inputClass} bg-gray-100 dark:bg-gray-700 text-gray-500 cursor-not-allowed`} />
               </div>
            </div>
          </div>

          {/* Theme Section */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
             <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 border-b border-gray-100 dark:border-gray-700 pb-2 flex items-center gap-2">
                <Palette size={18} className="text-primary-600" /> App Theme
             </h3>
             <div className="flex flex-wrap gap-4">
                 <ThemeButton t="teal" color="#14b8a6" />
                 <ThemeButton t="blue" color="#3b82f6" />
                 <ThemeButton t="violet" color="#8b5cf6" />
                 <ThemeButton t="rose" color="#f43f5e" />
                 <ThemeButton t="orange" color="#f97316" />
                 <ThemeButton t="gradient" color="" />
             </div>
             <p className="text-xs text-gray-500 mt-2">Select a theme to change the system-wide color palette.</p>
          </div>

          {/* Modules Section */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
             <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 border-b border-gray-100 dark:border-gray-700 pb-2 flex items-center gap-2">
                <Layers size={18} className="text-primary-600" /> Active Modules
             </h3>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                <ModuleToggle k="enableInventory" label="Inventory" desc="Stock management system" />
                <ModuleToggle k="enablePOS" label="Point of Sale" desc="Billing and Cart" />
                <ModuleToggle k="enableOrders" label="Supplier Orders" desc="Manage incoming stock" />
                <ModuleToggle k="enableSalesHistory" label="Sales History" desc="Transaction logs & receipts" />
                <ModuleToggle k="enableScanner" label="AI Scanner" desc="Doc & Prescription scan" />
                <ModuleToggle k="enableInsights" label="AI Insights" desc="Business analytics" />
             </div>
          </div>

          {/* Fields Section */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
             <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 border-b border-gray-100 dark:border-gray-700 pb-2 flex items-center gap-2">
                <List size={18} className="text-primary-600" /> Data Fields
             </h3>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div 
                    onClick={() => handleFieldToggle('showBatch')}
                    className={`flex items-center justify-between p-4 rounded-xl border-2 cursor-pointer transition ${formData.fields.showBatch ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700'}`}
                >
                    <div>
                        <h4 className="font-bold text-gray-800 dark:text-white text-sm">Batch Tracking</h4>
                    </div>
                    <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.fields.showBatch ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
                        {formData.fields.showBatch && <Check size={14} />}
                    </div>
                </div>

                <div 
                    onClick={() => handleFieldToggle('showExpiry')}
                    className={`flex items-center justify-between p-4 rounded-xl border-2 cursor-pointer transition ${formData.fields.showExpiry ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700'}`}
                >
                    <div>
                        <h4 className="font-bold text-gray-800 dark:text-white text-sm">Expiry Dates</h4>
                    </div>
                    <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.fields.showExpiry ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
                        {formData.fields.showExpiry && <Check size={14} />}
                    </div>
                </div>

                <div 
                    onClick={() => handleFieldToggle('showDoctor')}
                    className={`flex items-center justify-between p-4 rounded-xl border-2 cursor-pointer transition ${formData.fields.showDoctor ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20' : 'border-gray-100 dark:border-gray-700'}`}
                >
                    <div>
                        <h4 className="font-bold text-gray-800 dark:text-white text-sm">Doctor / Ref Field</h4>
                    </div>
                    <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.fields.showDoctor ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
                        {formData.fields.showDoctor && <Check size={14} />}
                    </div>
                </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

