import React, { useState, useRef, useEffect } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { CartItem, Medicine, Sale } from '../types';
import { ShoppingCart, Trash2, Printer, ScanBarcode, User, Stethoscope, Percent, Plus, Minus, X, LayoutTemplate } from 'lucide-react';

type BillTemplate = 'standard' | 'thermal' | 'modern';

const POS: React.FC = () => {
  const { inventory, processSale, formatDate, businessConfig, generateInvoiceId } = usePharmacy();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [barcodeInput, setBarcodeInput] = useState('');
  const [customerName, setCustomerName] = useState('Walk-in Customer');
  const [doctorName, setDoctorName] = useState('');
  const [showReceipt, setShowReceipt] = useState(false);
  const [lastSale, setLastSale] = useState<any>(null);
  const [receiptTemplate, setReceiptTemplate] = useState<BillTemplate>('standard');
  const barcodeInputRef = useRef<HTMLInputElement>(null);

  const productLabel = businessConfig?.labels.product || 'Item';
  const customerLabel = businessConfig?.labels.customer || 'Customer';
  const currency = businessConfig?.details.currency || '₹';

  const addToCart = (medicine: Medicine) => {
    if (medicine.quantity <= 0) {
      alert("Item out of stock!");
      return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.id === medicine.id);
      if (existing) {
        if (existing.cartQuantity >= medicine.quantity) {
          alert("Max stock reached for this item");
          return prev;
        }
        return prev.map(item => item.id === medicine.id ? { ...item, cartQuantity: item.cartQuantity + 1 } : item);
      }
      return [...prev, { ...medicine, cartQuantity: 1, discount: 0, gst: medicine.gst || 0 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateDiscount = (id: string, discount: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, discount } : item));
  };

  const updateGst = (id: string, gst: number) => {
    setCart(prev => prev.map(item => item.id === id ? { ...item, gst } : item));
  };

  const updateQuantity = (id: string, newQty: number) => {
    const itemInStock = inventory.find(i => i.id === id);
    if (!itemInStock) return;

    if (newQty > itemInStock.quantity) {
        alert(`Only ${itemInStock.quantity} available in stock.`);
        return;
    }

    if (newQty <= 0) {
        removeFromCart(id);
        return;
    }

    setCart(prev => prev.map(item => item.id === id ? { ...item, cartQuantity: newQty } : item));
  };

  const handleBarcodeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const product = inventory.find(i => i.barcode === barcodeInput || i.name.toLowerCase() === barcodeInput.toLowerCase());
    if (product) {
      addToCart(product);
      setBarcodeInput('');
    } else {
      alert(`${productLabel} not found!`);
    }
  };

  const calculateTotal = () => {
    return cart.reduce((acc, item) => {
      const discountedPrice = item.mrp * (1 - item.discount / 100);
      return acc + (discountedPrice * item.cartQuantity);
    }, 0);
  };

  const calculateTaxBreakdown = () => {
    let totalTax = 0;
    cart.forEach(item => {
        const lineTotal = item.mrp * (1 - item.discount / 100) * item.cartQuantity;
        const gstPercent = item.gst || 0;
        const taxAmount = (lineTotal * gstPercent) / (100 + gstPercent);
        totalTax += taxAmount;
    });
    return totalTax;
  };

  const calculateProfit = () => {
    return cart.reduce((acc, item) => {
      const revenueInclusive = item.mrp * (1 - item.discount / 100) * item.cartQuantity;
      const gstPercent = item.gst || 0;
      const revenueBase = revenueInclusive / (1 + (gstPercent/100));
      const cost = item.purchasePrice * item.cartQuantity;
      return acc + (revenueBase - cost);
    }, 0);
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;

    // Generate sequential ID
    const newId = generateInvoiceId();

    const sale = {
      id: newId,
      date: new Date().toISOString(),
      customerName,
      doctorName: businessConfig?.fields.showDoctor ? doctorName : undefined,
      items: [...cart],
      totalAmount: calculateTotal(),
      profit: calculateProfit()
    };

    processSale(sale);
    setLastSale(sale);
    setCart([]);
    setShowReceipt(true);
  };

  const printReceipt = () => {
    window.print();
  };

  const inputClass = "w-full px-4 py-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-800 dark:text-gray-200 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all shadow-sm text-sm font-medium";

  // --- Render Templates ---

  const renderThermalReceipt = () => {
    const totalTax = calculateTaxBreakdown(); // This needs to be calculated from lastSale items for accurate history
    // Re-calculate tax for display based on stored sale items
    let displayTotalTax = 0;
    if(lastSale){
