                  <button onClick={() => setReceiptTemplate('standard')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'standard' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Standard</button>
                  <button onClick={() => setReceiptTemplate('thermal')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'thermal' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Thermal</button>
                  <button onClick={() => setReceiptTemplate('modern')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'modern' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Modern</button>
               </div>
               <div className="flex gap-2">
                    <button onClick={() => setShowReceipt(false)} className="bg-white p-2 md:p-3 rounded-full text-gray-600 hover:text-red-600 shadow-lg hover:bg-gray-100 transition">
                        <X size={20} />
                    </button>
                    <button onClick={printReceipt} className="bg-primary-600 p-2 md:p-3 rounded-full text-white shadow-lg hover:bg-primary-700 transition">
                        <Printer size={20} />
                    </button>
               </div>
            </div>

            {/* Printable Content Area */}
            <div id="printable-area" className="flex-1 bg-white rounded-lg overflow-hidden">
                {receiptTemplate === 'standard' && renderStandardReceipt()}
                {receiptTemplate === 'thermal' && renderThermalReceipt()}
                {receiptTemplate === 'modern' && renderModernReceipt()}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

