          <h1 className="text-xl font-bold text-primary-700 dark:text-primary-400 flex items-center gap-2 truncate" title={businessConfig.details.name}>
            <div className="w-8 h-8 bg-primary-600 rounded-lg flex items-center justify-center text-white text-lg shrink-0 shadow-sm shadow-primary-600/30">
                {businessConfig.details.name.charAt(0)}
            </div>
            {businessConfig.details.name}
          </h1>
        </div>
        <nav className="flex-1 py-4 space-y-1 overflow-y-auto">
          <NavItem view={AppView.DASHBOARD} icon={LayoutDashboard} label="Dashboard" />

          {modules.enableInventory && (
             <NavItem view={AppView.INVENTORY} icon={Boxes} label={`Inventory (${businessConfig.labels.product})`} />
          )}

          {modules.enablePOS && (
             <NavItem view={AppView.POS} icon={ShoppingCart} label="POS & Billing" />
          )}

          {modules.enableOrders && (
             <NavItem view={AppView.ORDERS} icon={Truck} label="Orders" />
