        {/* Settings & Toggles */}
        <div className="p-4 border-t border-gray-100 dark:border-gray-700 space-y-2">
           <button 
             onClick={toggleDarkMode}
             className="w-full py-2 rounded-lg flex items-center justify-center gap-2 text-sm font-medium transition bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
           >
             {isDarkMode ? <Sun size={16}/> : <Moon size={16}/>} {isDarkMode ? 'Light Mode' : 'Dark Mode'}
           </button>
           <button 
             onClick={handleTogglePaid}
             className={`w-full py-2 rounded-lg flex items-center justify-center gap-2 text-sm font-bold transition ${isPaid ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300' : 'bg-gray-100 text-gray-500 dark:bg-gray-700 dark:text-gray-400 hover:bg-gray-200'}`}
           >
             <Crown size={16} /> {isPaid ? 'Pro Plan Active' : 'Upgrade to Pro'}
           </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-gray-800 border-b dark:border-gray-700 z-20 flex items-center justify-between p-4 transition-colors duration-200">
        <h1 className="font-bold text-primary-700 dark:text-primary-400 text-lg flex items-center gap-2">
            <div className="w-6 h-6 bg-primary-600 rounded-md flex items-center justify-center text-white text-xs shrink-0 shadow-sm">
                {businessConfig.details.name.charAt(0)}
