        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="text-gray-600 dark:text-gray-300">
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="md:hidden fixed inset-0 bg-white dark:bg-gray-800 z-10 pt-16 transition-colors duration-200">
          <nav className="p-4 space-y-2 overflow-y-auto max-h-full">
            <NavItem view={AppView.DASHBOARD} icon={LayoutDashboard} label="Dashboard" />

            {modules.enableInventory && (
                <NavItem view={AppView.INVENTORY} icon={Boxes} label="Inventory" />
            )}

            {modules.enablePOS && (
                <NavItem view={AppView.POS} icon={ShoppingCart} label="POS" />
            )}

            {modules.enableOrders && (
                <NavItem view={AppView.ORDERS} icon={Truck} label="Orders" />
            )}

            {modules.enableSalesHistory && (
                <NavItem view={AppView.SALES_HISTORY} icon={ClipboardList} label="Sales History" />
            )}

            {modules.enableScanner && (
                <NavItem view={AppView.AI_SCANNER} icon={FileText} label="AI Scanner" />
            )}

            {modules.enableInsights && (
                <NavItem view={AppView.INSIGHTS} icon={Sparkles} label="AI Insights" highlight />
            )}

            <NavItem view={AppView.CONFIGURATION} icon={Settings} label="Configuration" />

            <div className="pt-4 mt-4 border-t border-gray-100 dark:border-gray-700 flex gap-2">
                <button onClick={toggleDarkMode} className="flex-1 py-3 bg-gray-100 dark:bg-gray-700 rounded-lg flex justify-center text-gray-600 dark:text-white">
                    {isDarkMode ? <Sun size={20}/> : <Moon size={20}/>}
                </button>
                <button onClick={handleTogglePaid} className={`flex-1 py-3 rounded-lg flex justify-center font-bold ${isPaid ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-500'}`}>
                    <Crown size={20}/>
                </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 overflow-auto md:p-6 pt-16 md:pt-6 relative w-full">
        {children}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { Medicine, Category } from '../types';
import { Plus, Search, Trash2, Edit, X, Check, Package, Barcode, Calendar, Copy, ChevronDown, List, Settings } from 'lucide-react';

// Optimized Barcode Component (Outside render loop)
const BarcodeVisual = React.memo(({ code }: { code: string }) => (
  <div className="flex flex-col items-center p-2 bg-white dark:bg-gray-100 border border-gray-200 rounded shadow-sm w-fit">
    <div className="flex items-end h-6 space-x-[1px]">
      {code.split('').map((char, i) => (
        <div 
          key={i} 
          className={`w-[1px] md:w-[2px] bg-black ${parseInt(char) % 2 === 0 ? 'h-full' : 'h-3/4'}`}
        />
      ))}
    </div>
    <span className="text-[9px] tracking-widest font-mono mt-1 text-gray-500">{code}</span>
  </div>
));

const Inventory: React.FC = () => {
  const { 
    inventory, updateMedicine, deleteMedicine, addMedicine,
    inventorySearchTerm, setInventorySearchTerm, formatDate, 
    businessConfig, categories, updateCategory, addCategory 
  } = usePharmacy();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Config shorthands
  const showBatch = businessConfig?.fields.showBatch ?? true;
  const showExpiry = businessConfig?.fields.showExpiry ?? true;
  const productLabel = businessConfig?.labels.product ?? 'Medicine';
  const defaultGlobalGst = businessConfig?.details.defaultGst || 0;

  // Filter States
  const [filterCategory, setFilterCategory] = useState('All');
  const [filterStatus, setFilterStatus] = useState('All');

  // Add Stock Dropdown State
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [productSearch, setProductSearch] = useState('');

  // Initial Form State
  const initialFormState: Partial<Medicine> = {
    name: '',
    category: 'General',
    quantity: 0,
    purchasePrice: 0,
    mrp: 0,
    batchNumber: '',
    expiryDate: '',
    barcode: '',
    gst: defaultGlobalGst
  };

  const [formData, setFormData] = useState<Partial<Medicine>>(initialFormState);

  // Category Manager State
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [newCatGst, setNewCatGst] = useState(defaultGlobalGst);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Auto-update GST when category changes
    if (name === 'category') {
        const catObj = categories.find(c => c.name === value);
        if (catObj) {
            setFormData(prev => ({ ...prev, category: value, gst: catObj.gst }));
            return;
        }
    }

    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' || name === 'purchasePrice' || name === 'mrp' || name === 'gst' ? parseFloat(value) : value
    }));
  };

  const generateBarcode = () => {
    const timestamp = Date.now().toString().slice(-12);
    return `8${timestamp}`;
  };

  const handleEdit = (item: Medicine) => {
    setFormData(item);
    setProductSearch(item.name);
    setEditingId(item.id);
    setIsModalOpen(true);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Are you sure you want to delete this item?')) {
      deleteMedicine(id);
    }
  };

  const handleProductSelect = (item: Medicine) => {
    setFormData(prev => ({
      ...prev,
      name: item.name,
      category: item.category,
      purchasePrice: item.purchasePrice,
      mrp: item.mrp,
      batchNumber: item.batchNumber,
      expiryDate: item.expiryDate,
      barcode: item.barcode,
      gst: item.gst,
      quantity: 0 
    }));

    setProductSearch(item.name);
    setIsDropdownOpen(false);
  };

  const handleNewBatchSelect = (name: string, category: string) => {
    const catObj = categories.find(c => c.name === category);
    setFormData(prev => ({
      ...initialFormState,
      name: name,
      category: category,
      barcode: generateBarcode(),
      gst: catObj ? catObj.gst : defaultGlobalGst
    }));
    setProductSearch(name);
    setIsDropdownOpen(false);
  };

  const findExactMatch = () => {
     return inventory.find(i => 
        i.name.toLowerCase() === productSearch.toLowerCase() &&
        (showBatch ? i.batchNumber === formData.batchNumber : true) &&
        (showExpiry ? i.expiryDate === formData.expiryDate : true) &&
        i.mrp === formData.mrp &&
        i.purchasePrice === formData.purchasePrice &&
        i.barcode === formData.barcode
      );
  };

  const handleSaveExisting = () => {
    const exactMatch = findExactMatch();
    if (exactMatch) {
        updateMedicine(exactMatch.id, { quantity: exactMatch.quantity + (formData.quantity || 0) });
        closeModal();
    } else {
        alert("Cannot update existing stock: Details do not match exactly with any existing batch.");
    }
  };

  const handleSaveAsNew = () => {
     if (!productSearch) return;
     if (showBatch && !formData.batchNumber) { alert("Batch number required"); return; }

     const newMedicine: Medicine = {
        id: Date.now().toString(),
        name: productSearch,
        batchNumber: formData.batchNumber || '',
        expiryDate: formData.expiryDate || new Date().toISOString().split('T')[0],
        quantity: formData.quantity || 0,
        purchasePrice: formData.purchasePrice || 0,
        mrp: formData.mrp || 0,
        barcode: formData.barcode || generateBarcode(),
        category: formData.category || 'General',
        gst: formData.gst || 0
    };
    addMedicine(newMedicine);
    closeModal();
  };

  const handleUpdate = () => {
    if (editingId) {
        updateMedicine(editingId, { ...formData, name: productSearch } as Medicine);
        closeModal();
    }
  }

  const closeModal = () => {
    setIsModalOpen(false);
    setFormData(initialFormState);
    setProductSearch('');
    setEditingId(null);
  };

  const openAddModal = () => {
      setFormData(initialFormState);
      setProductSearch('');
      setEditingId(null);
      setIsModalOpen(true);
  }

  // --- Category Manager Logic ---
  const handleAddCategory = () => {
      if (newCatName) {
          addCategory(newCatName, newCatGst);
          setNewCatName('');
          setNewCatGst(defaultGlobalGst);
      }
  };

  const handleUpdateCategory = (cat: Category) => {
      updateCategory(cat.id, { name: cat.name, gst: cat.gst });
      setEditingCategory(null);
  };

  const filteredInventory = useMemo(() => {
    return inventory.filter(item => {
      const matchesSearch = 
        item.name.toLowerCase().includes(inventorySearchTerm.toLowerCase()) ||
        item.barcode.includes(inventorySearchTerm) ||
        (showBatch && item.batchNumber.toLowerCase().includes(inventorySearchTerm.toLowerCase()));

      const matchesCategory = filterCategory === 'All' || item.category === filterCategory;

      let matchesStatus = true;
      if (filterStatus === 'Low Stock') matchesStatus = item.quantity < 50 && item.quantity > 0;
      else if (filterStatus === 'Out of Stock') matchesStatus = item.quantity === 0;
      else if (filterStatus === 'Expired' && showExpiry) matchesStatus = new Date(item.expiryDate) < new Date();

      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [inventory, inventorySearchTerm, filterCategory, filterStatus, showBatch, showExpiry]);

  const getExpiryColorClass = (dateStr: string) => {
    if (!showExpiry) return '';
    const today = new Date();
    const expiry = new Date(dateStr);
    const diffTime = expiry.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'text-red-600 bg-red-50 dark:bg-red-900/30 border-red-200 dark:border-red-900 ring-1 ring-red-100 dark:ring-red-900/50'; 
    if (diffDays <= 15) return 'text-yellow-700 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-900/30 border-yellow-200 dark:border-yellow-900 ring-1 ring-yellow-100 dark:ring-yellow-900/50'; 
    if (diffDays <= 30) return 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900/30 border-orange-200 dark:border-orange-900 ring-1 ring-orange-100 dark:ring-orange-900/50'; 
    return 'text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/30 border-green-200 dark:border-green-900'; 
  };

  const exactMatchFound = findExactMatch();
  const inputClass = "w-full px-4 py-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-800 dark:text-gray-200 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all shadow-sm text-sm font-medium";
  const selectClass = "w-full pl-4 pr-10 py-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-800 dark:text-gray-200 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all shadow-sm text-sm font-medium appearance-none cursor-pointer";

  return (
    <div className="p-4 bg-gray-50/50 dark:bg-gray-900/50 min-h-screen">
      {/* Header Controls */}
      <div className="flex flex-col gap-4 mb-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <Package className="text-primary-600 dark:text-primary-400"/> Inventory Management
            </h2>
            <div className="flex gap-2 w-full md:w-auto">
                <button 
                    onClick={() => setIsCategoryManagerOpen(true)}
                    className="flex items-center justify-center gap-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-200 px-4 py-2.5 rounded-xl hover:bg-gray-50 dark:hover:bg-gray-700 transition shadow-sm font-medium"
                >
                    <List size={18} /> Categories
                </button>
                <button 
                    onClick={openAddModal}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 text-white px-6 py-2.5 rounded-xl hover:from-primary-700 hover:to-primary-600 transition shadow-md font-medium"
                >
                    <Plus size={18} /> Add {productLabel}
                </button>
            </div>
        </div>

        {/* Improved Search and Filter Bar */}
        <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-sm flex flex-col xl:flex-row gap-4">
             <div className="relative flex-1">
                <Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
                <input 
                    type="text"
                    placeholder={`Search ${productLabel.toLowerCase()}, ${showBatch ? 'batch,' : ''} barcode...`}
                    className={`${inputClass} pl-10`}
                    value={inventorySearchTerm}
                    onChange={(e) => setInventorySearchTerm(e.target.value)}
                />
            </div>

            <div className="flex flex-col sm:flex-row gap-4">
                <div className="relative min-w-[200px]">
                  <select 
                      value={filterCategory}
                      onChange={(e) => setFilterCategory(e.target.value)}
                      className={selectClass}
                  >
                      <option value="All">All Categories</option>
                      {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                  </select>
                  <ChevronDown className="absolute right-3 top-3.5 text-gray-400 pointer-events-none" size={16}/>
                </div>

                <div className="relative min-w-[200px]">
                  <div className={`absolute left-4 top-4 w-2 h-2 rounded-full z-10 pointer-events-none ${filterStatus === 'All' ? 'hidden' : filterStatus === 'Low Stock' ? 'bg-orange-500' : 'bg-red-500'}`}></div>
                  <select 
                      value={filterStatus}
                      onChange={(e) => setFilterStatus(e.target.value)}
                      className={`${selectClass} ${filterStatus !== 'All' ? 'pl-8' : ''}`}
                  >
                      <option value="All">All Status</option>
                      <option value="Low Stock">Low Stock</option>
                      <option value="Out of Stock">Out of Stock</option>
                      {showExpiry && <option value="Expired">Expired</option>}
                  </select>
                  <ChevronDown className="absolute right-3 top-3.5 text-gray-400 pointer-events-none" size={16}/>
                </div>
            </div>
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-x-auto relative">
            <table className="w-full text-left border-collapse min-w-[900px]">
            <thead className="bg-gray-50 dark:bg-gray-700 text-gray-600 dark:text-gray-300 text-xs uppercase tracking-wider border-b border-gray-200 dark:border-gray-600 shadow-sm">
                <tr>
                {/* Sticky First Column Header */}
                <th className="p-4 font-semibold min-w-[220px] sticky left-0 z-20 bg-gray-50 dark:bg-gray-700 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">{productLabel}</th>

                {(showBatch || showExpiry) && <th className="p-4 font-semibold min-w-[140px]">Batch Info</th>}
                <th className="p-4 font-semibold min-w-[100px]">Stock</th>
                <th className="p-4 font-semibold min-w-[140px]">Pricing & Tax</th>
                <th className="p-4 font-semibold min-w-[140px] hidden xl:table-cell">Barcode</th>
                <th className="p-4 font-semibold text-center min-w-[100px]">Actions</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                {filteredInventory.length > 0 ? filteredInventory.map(item => (
                <tr key={item.id} className="group hover:bg-primary-50/20 dark:hover:bg-primary-900/20 transition-colors duration-150">
                    {/* Sticky First Column Data */}
                    <td className="p-4 sticky left-0 z-20 bg-white dark:bg-gray-800 group-hover:bg-primary-50/20 dark:group-hover:bg-primary-900/20 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)] border-r border-gray-100 dark:border-gray-700/50">
                    <div className="font-bold text-gray-800 dark:text-gray-200 text-sm md:text-base">{item.name}</div>
                    <div className="flex flex-wrap gap-2 mt-1.5">
                       <span className="text-[10px] font-medium text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded-full border border-gray-200 dark:border-gray-600">{item.category}</span>
                    </div>
                    </td>
                    {(showBatch || showExpiry) && (
                        <td className="p-4">
                        <div className="flex flex-col gap-1">
                            {showBatch && <span className="text-xs font-mono text-gray-600 dark:text-gray-300 bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded w-fit">Batch: {item.batchNumber}</span>}
                            {showExpiry && (
                                <div className={`text-xs font-bold px-2 py-1 rounded w-fit flex items-center gap-1 ${getExpiryColorClass(item.expiryDate)}`}>
                                    <Calendar size={10}/> {formatDate(item.expiryDate)}
                                </div>
                            )}
                        </div>
                        </td>
                    )}
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                        <span className={`px-2.5 py-1 rounded-full text-xs font-bold shadow-sm ${item.quantity === 0 ? 'bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 border border-gray-200 dark:border-gray-600' : item.quantity < 50 ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border border-red-100 dark:border-red-900/30' : 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-900/30'}`}>
                            {item.quantity} units
                        </span>
                        {item.quantity === 0 && <span className="text-[10px] text-red-500 font-bold uppercase tracking-wide">Out</span>}
                      </div>
                    </td>
                    <td className="p-4">
                      <div className="space-y-1">
                        <div className="flex items-center justify-between text-xs text-gray-500 dark:text-gray-400 max-w-[120px]">
                           <span>Buy:</span> <span className="font-mono">{businessConfig?.details.currency}{item.purchasePrice}</span>
                        </div>
                        <div className="flex items-center justify-between text-sm font-bold text-primary-700 dark:text-primary-400 max-w-[120px] bg-primary-50 dark:bg-primary-900/30 px-2 py-0.5 rounded border border-primary-100 dark:border-primary-900/50">
                           <span>Sell:</span> <span>{businessConfig?.details.currency}{item.mrp}</span>
                        </div>
                        <div className="flex items-center justify-between text-xs text-gray-400 dark:text-gray-500 max-w-[120px]">
                            <span>GST:</span> <span>{item.gst || 0}%</span>
                        </div>
                      </div>
                    </td>
                    <td className="p-4 hidden xl:table-cell">
                      <BarcodeVisual code={item.barcode} />
                    </td>
                    <td className="p-4 text-center">
                    <div className="flex justify-center gap-2 opacity-100">
