import React, { useState } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { Sale } from '../types';
import { Search, Calendar, Filter, X, Printer, ArrowDown, ArrowUp, FileText, DollarSign, User } from 'lucide-react';

type BillTemplate = 'standard' | 'thermal' | 'modern';

const SalesHistory: React.FC = () => {
  const { sales, formatDate, businessConfig } = usePharmacy();
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSale, setSelectedSale] = useState<Sale | null>(null);
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [dateFilter, setDateFilter] = useState('');
  const [receiptTemplate, setReceiptTemplate] = useState<BillTemplate>('standard');

  const currency = businessConfig?.details.currency || '$';
  const customerLabel = businessConfig?.labels.customer || 'Customer';
  const productLabel = businessConfig?.labels.product || 'Product';

  const filteredSales = sales.filter(sale => {
    const matchesSearch = 
      sale.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || 
      sale.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesDate = dateFilter ? sale.date.startsWith(dateFilter) : true;

    return matchesSearch && matchesDate;
  }).sort((a, b) => {
    const dateA = new Date(a.date).getTime();
    const dateB = new Date(b.date).getTime();
    return sortOrder === 'desc' ? dateB - dateA : dateA - dateB;
  });

  const printReceipt = () => {
    const element = document.getElementById('printable-area');
    if (element && (window as any).html2pdf) {
        const opt = {
            margin:       10,
            filename:     `Invoice_${selectedSale?.id}.pdf`,
            image:        { type: 'jpeg', quality: 0.98 },
            html2canvas:  { scale: 2 },
            jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };
        // @ts-ignore
        (window as any).html2pdf().set(opt).from(element).save().then(() => {
            window.print();
        });
    } else {
        window.print();
    }
  };

  const inputClass = "w-full px-4 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-800 dark:text-gray-200 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all shadow-sm text-sm font-medium";

  // --- Render Templates (Identical to POS for consistency) ---
  const renderThermalReceipt = () => {
    if (!selectedSale) return null;
    let displayTotalTax = 0;
    selectedSale.items.forEach((item: any) => {
        const lineTotal = item.mrp * (1 - (item.discount || 0) / 100) * item.cartQuantity;
        const gstPercent = item.gst || 0;
        const taxAmount = (lineTotal * gstPercent) / (100 + gstPercent);
        displayTotalTax += taxAmount;
    });

    return (
        <div className="w-[80mm] p-2 bg-white text-black font-mono text-xs mx-auto">
            <div className="text-center mb-4 border-b border-black pb-2">
                <h1 className="font-bold text-lg uppercase">{businessConfig?.details.name}</h1>
                <p>{businessConfig?.details.address}</p>
                <p>{businessConfig?.details.contact}</p>
                {businessConfig?.details.gstin && <p>GSTIN: {businessConfig.details.gstin}</p>}
            </div>
            <div className="mb-2">
                <p>Date: {formatDate(selectedSale.date)} {new Date(selectedSale.date).toLocaleTimeString()}</p>
                <p>Bill No: {selectedSale.id}</p>
                <p>Cust: {selectedSale.customerName}</p>
                {selectedSale.doctorName && <p>Dr: {selectedSale.doctorName}</p>}
            </div>
            <div className="border-t border-b border-black py-1 mb-2">
                <div className="flex font-bold">
                    <span className="w-1/2">Item</span>
                    <span className="w-1/6 text-center">Qty</span>
                    <span className="w-1/3 text-right">Amt</span>
                </div>
            </div>
            {selectedSale.items.map((item: any, idx: number) => {
                const itemTotal = item.mrp * (1 - (item.discount || 0) / 100) * item.cartQuantity;
                return (
                    <div key={idx} className="mb-1 border-b border-gray-100 pb-1">
                        <div>{item.name}</div>
                        <div className="flex text-[10px] text-gray-600">
                            {businessConfig?.fields.showBatch && <span className="mr-2">B:{item.batchNumber}</span>}
                        </div>
                        <div className="flex">
                            <span className="w-1/2 text-[10px] pl-1">GST:{item.gst}%</span>
                            <span className="w-1/6 text-center">{item.cartQuantity}</span>
                            <span className="w-1/3 text-right">{itemTotal.toFixed(2)}</span>
                        </div>
                    </div>
                )
            })}
            <div className="border-t border-black pt-2 mt-2 space-y-1">
                <div className="flex justify-between text-[10px]">
                    <span>Taxable Amt</span>
                    <span>{currency}{(selectedSale.totalAmount - displayTotalTax).toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-[10px]">
                    <span>Total Tax (GST)</span>
                    <span>{currency}{displayTotalTax.toFixed(2)}</span>
                </div>
                <div className="flex justify-between font-bold text-sm border-t border-dashed border-gray-400 pt-1">
                    <span>TOTAL</span>
                    <span>{currency}{selectedSale.totalAmount.toFixed(2)}</span>
                </div>
            </div>
            <div className="text-center mt-4 text-[10px]">
                <p>Thank You Visit Again</p>
            </div>
        </div>
    );
  };

  const renderModernReceipt = () => {
     if (!selectedSale) return null;
     let displayTotalTax = 0;
     selectedSale.items.forEach((item: any) => {
        const lineTotal = item.mrp * (1 - (item.discount || 0) / 100) * item.cartQuantity;
        const gstPercent = item.gst || 0;
        const taxAmount = (lineTotal * gstPercent) / (100 + gstPercent);
        displayTotalTax += taxAmount;
    });

     return (
        <div className="p-8 bg-white text-gray-800 h-full font-sans border-t-8 border-primary-600">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-primary-800">{businessConfig?.details.name}</h1>
                    {businessConfig?.details.gstin && <p className="text-sm font-bold text-gray-500 mt-1">GSTIN: {businessConfig.details.gstin}</p>}
                </div>
                <div className="text-right">
                    <p className="text-sm text-gray-500">INVOICE #{selectedSale.id}</p>
                    <p className="font-bold text-lg">{formatDate(selectedSale.date)}</p>
                </div>
            </div>
            <div className="flex gap-8 mb-8 bg-gray-50 p-6 rounded-lg">
                 <div className="flex-1">
                     <p className="text-xs uppercase font-bold text-gray-400 mb-1">Billed To</p>
                     <p className="font-bold text-lg">{selectedSale.customerName}</p>
                     {selectedSale.doctorName && <p className="text-sm">Ref: Dr. {selectedSale.doctorName}</p>}
                 </div>
                 <div className="flex-1 text-right">
                     <p className="text-xs uppercase font-bold text-gray-400 mb-1">Pay To</p>
                     <p className="font-bold">{businessConfig?.details.name}</p>
                     <p className="text-sm">{businessConfig?.details.address}</p>
                     <p className="text-sm">{businessConfig?.details.contact}</p>
                 </div>
            </div>
            <table className="w-full mb-8">
                <thead className="bg-primary-600 text-white">
                    <tr>
                        <th className="p-3 text-left rounded-l-lg">Description</th>
                        <th className="p-3 text-center">Qty</th>
                        <th className="p-3 text-center">GST%</th>
                        <th className="p-3 text-right">Price</th>
                        <th className="p-3 text-right rounded-r-lg">Total</th>
                    </tr>
                </thead>
                <tbody>
                     {selectedSale.items.map((item: any, idx: number) => (
                         <tr key={idx} className="border-b border-gray-100">
                             <td className="p-3">
                                 <p className="font-bold">{item.name}</p>
                                 <p className="text-xs text-gray-500">{item.batchNumber}</p>
                             </td>
                             <td className="p-3 text-center">{item.cartQuantity}</td>
                             <td className="p-3 text-center">{item.gst}%</td>
                             <td className="p-3 text-right">{currency}{item.mrp}</td>
                             <td className="p-3 text-right font-bold">{currency}{(item.mrp * (1 - (item.discount || 0) / 100) * item.cartQuantity).toFixed(2)}</td>
                         </tr>
                     ))}
                </tbody>
            </table>
            <div className="flex justify-end">
                <div className="w-1/2 bg-primary-50 p-4 rounded-lg">
                    <div className="flex justify-between mb-2 text-sm">
                        <span>Taxable Amount</span>
                        <span>{currency}{(selectedSale.totalAmount - displayTotalTax).toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between mb-2 text-sm">
                        <span>Total GST</span>
                        <span>{currency}{displayTotalTax.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between font-bold text-xl text-primary-800 pt-2 border-t border-primary-200">
                        <span>Grand Total</span>
                        <span>{currency}{selectedSale.totalAmount.toFixed(2)}</span>
                    </div>
                </div>
            </div>
        </div>
     );
  };

  const renderStandardReceipt = () => {
      if (!selectedSale) return null;
      return (
        <div className="p-[10mm] text-gray-800 text-sm font-sans flex flex-col h-full">
            <div className="flex justify-between items-start border-b-2 border-gray-800 pb-4 mb-6">
                <div>
                    <h1 className="text-3xl font-bold text-primary-800 mb-1">{businessConfig?.details.name || 'Store Name'}</h1>
                    <div className="mt-2 text-xs text-gray-500 space-y-0.5">
                        <p>{businessConfig?.details.address}</p>
                        <p>{businessConfig?.details.contact}</p>
                    </div>
                </div>
                <div className="text-right">
                    <h2 className="text-xl font-bold text-gray-400 uppercase tracking-widest">Tax Invoice</h2>
                    <p className="font-mono mt-2 font-bold text-lg">#{selectedSale.id}</p>
                    {businessConfig?.details.gstin && <p className="text-xs text-gray-500 font-bold">GSTIN: {businessConfig.details.gstin}</p>}
                </div>
            </div>

            <div className="flex justify-between mb-6 bg-gray-50 p-4 rounded border border-gray-100">
                <div className="space-y-1">
                    <p className="text-xs text-gray-500 uppercase font-bold tracking-wider">Billed To</p>
                    <p className="font-bold text-lg text-gray-800">{selectedSale.customerName}</p>
                    {selectedSale.doctorName && <p className="text-sm text-gray-600">Dr. {selectedSale.doctorName}</p>}
                </div>
                <div className="text-right space-y-1">
                    <p className="text-xs text-gray-500 uppercase font-bold tracking-wider">Invoice Details</p>
                    <p><span className="text-gray-500">Date:</span> <span className="font-medium">{formatDate(selectedSale.date)}</span></p>
                    <p><span className="text-gray-500">Time:</span> <span className="font-medium">{new Date(selectedSale.date).toLocaleTimeString()}</span></p>
                </div>
            </div>

            <div className="flex-1">
                <table className="w-full text-left mb-6">
                    <thead>
                    <tr className="border-b-2 border-gray-800 text-xs uppercase font-bold text-gray-600">
                        <th className="py-2 pr-2 w-8 text-center">#</th>
                        <th className="py-2 pr-2">{productLabel} Description</th>
                        {businessConfig?.fields.showBatch && <th className="py-2 pr-2 w-20">Batch</th>}
                        <th className="py-2 pr-2 w-12 text-center">Qty</th>
                        <th className="py-2 pr-2 w-16 text-right">Rate</th>
                        <th className="py-2 pr-2 w-12 text-center">Disc%</th>
                        <th className="py-2 pr-2 w-12 text-center">GST%</th>
                        <th className="py-2 pl-2 w-20 text-right">Amount</th>
                    </tr>
                    </thead>
                    <tbody className="text-sm">
                    {selectedSale.items.map((item: any, idx: number) => {
                        const itemTotal = item.mrp * (1 - (item.discount || 0) / 100) * item.cartQuantity;
                        return (
                        <tr key={idx} className="border-b border-gray-100">
                            <td className="py-3 text-center text-gray-500">{idx + 1}</td>
                            <td className="py-3 font-medium text-gray-800">
                                {item.name}
                                <div className="text-[10px] text-gray-400">{item.category}</div>
                            </td>
                            {businessConfig?.fields.showBatch && <td className="py-3 font-mono text-xs">{item.batchNumber}</td>}
                            <td className="py-3 text-center">{item.cartQuantity}</td>
                            <td className="py-3 text-right">{currency}{item.mrp}</td>
                            <td className="py-3 text-center">{item.discount > 0 ? item.discount + '%' : '-'}</td>
                            <td className="py-3 text-center">{item.gst}%</td>
                            <td className="py-3 text-right font-bold">{currency}{itemTotal.toFixed(2)}</td>
                        </tr>
                        );
                    })}
                    </tbody>
                </table>
            </div>

            <div className="border-t-2 border-gray-800 pt-4 mb-8">
                <div className="flex justify-end">
                    <div className="w-72 space-y-2">
                        {(() => {
                            const totalWithTax = selectedSale.items.reduce((acc:any, i:any) => acc + (i.mrp * (1 - (i.discount || 0)/100) * i.cartQuantity), 0);
                            let totalTax = 0;
                            let totalBase = 0;

                            selectedSale.items.forEach((i:any) => {
                                const lineTotal = i.mrp * (1 - (i.discount || 0)/100) * i.cartQuantity;
                                const taxRate = i.gst || 0;
                                const taxAmt = (lineTotal * taxRate) / (100 + taxRate);
                                totalTax += taxAmt;
                                totalBase += (lineTotal - taxAmt);
                            });

                            const cgst = totalTax / 2;
                            const sgst = totalTax / 2;

                            return (
                                <>
                                <div className="flex justify-between text-gray-600 text-sm">
                                    <span>Taxable Value</span>
                                    <span>{currency}{totalBase.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-gray-600 text-sm">
                                    <span>CGST</span>
                                    <span>{currency}{cgst.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-gray-600 text-sm">
                                    <span>SGST</span>
                                    <span>{currency}{sgst.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-gray-600 text-sm border-t border-dashed pt-1 mt-1">
                                    <span>Total Tax</span>
                                    <span>{currency}{totalTax.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between font-bold text-xl border-t border-gray-300 pt-2 mt-2 text-gray-900">
                                    <span>Grand Total</span>
                                    <span>{currency}{totalWithTax.toFixed(2)}</span>
                                </div>
                                </>
                            );
                        })()}
                    </div>
                </div>
            </div>

            <div className="mt-auto grid grid-cols-2 gap-8 text-xs text-gray-500">
                <div>
                    <h4 className="font-bold text-gray-700 mb-1 uppercase">Terms & Conditions</h4>
                    <ul className="list-disc pl-4 space-y-0.5">
                        <li>Goods once sold will not be taken back.</li>
                        <li>Prices are inclusive of GST.</li>
                        <li>Thank you for your business!</li>
                    </ul>
                </div>
                <div className="flex flex-col justify-end items-end text-center">
                    <div className="h-16 w-32 border-b border-gray-300 mb-1"></div>
                    <p>Authorized Signatory</p>
                </div>
            </div>
        </div>
      );
  };

  return (
    <div className="p-4 h-full flex flex-col bg-gray-50/50 dark:bg-gray-900/50">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
        <div>
           <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
             <FileText className="text-primary-600 dark:text-primary-400" /> Sales History
           </h2>
           <p className="text-sm text-gray-500 dark:text-gray-400">Track and manage past transactions.</p>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 mb-6 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
            <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
            <input 
                type="text"
                placeholder={`Search by ${customerLabel.toLowerCase()} or Bill ID...`}
                className={`${inputClass} pl-10`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
        </div>
        <div className="relative w-full md:w-48">
             <input 
                type="date"
                className={inputClass}
                value={dateFilter}
                onChange={(e) => setDateFilter(e.target.value)}
            />
        </div>
        <button 
            onClick={() => setSortOrder(prev => prev === 'desc' ? 'asc' : 'desc')}
            className="flex items-center gap-2 px-4 py-2 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-200 transition"
        >
            <Filter size={16} /> 
            Sort: {sortOrder === 'desc' ? 'Newest' : 'Oldest'}
            {sortOrder === 'desc' ? <ArrowDown size={14} /> : <ArrowUp size={14} />}
        </button>
      </div>

      {/* Sales List */}
      <div className="flex-1 overflow-y-auto">
         {filteredSales.length === 0 ? (
             <div className="flex flex-col items-center justify-center py-12 text-center text-gray-400 dark:text-gray-500">
                 <FileText size={48} className="mb-4 opacity-50"/>
                 <p className="text-lg font-medium">No records found</p>
                 <p className="text-sm">Try adjusting your filters.</p>
             </div>
         ) : (
            <div className="grid gap-3">
                {filteredSales.map(sale => (
                    <div 
                        key={sale.id}
                        onClick={() => setSelectedSale(sale)}
                        className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 hover:shadow-md hover:border-primary-200 dark:hover:border-primary-900 transition cursor-pointer flex flex-col md:flex-row justify-between items-center gap-4"
                    >
                        <div className="flex items-start gap-4 flex-1 w-full">
                            <div className="p-3 bg-primary-50 dark:bg-primary-900/20 rounded-full text-primary-600 dark:text-primary-400 hidden sm:block">
                                <DollarSign size={20} />
                            </div>
                            <div>
                                <h3 className="font-bold text-gray-800 dark:text-gray-100 text-lg">{sale.customerName}</h3>
                                <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-sm text-gray-500 dark:text-gray-400">
                                    <span className="flex items-center gap-1"><Calendar size={14}/> {new Date(sale.date).toLocaleString()}</span>
                                    <span className="font-mono bg-gray-100 dark:bg-gray-700 px-2 rounded text-xs py-0.5">#{sale.id}</span>
                                    {sale.doctorName && <span className="flex items-center gap-1"><User size={14}/> Dr. {sale.doctorName}</span>}
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-between w-full md:w-auto gap-8">
                             <div className="text-right">
                                <div className="text-xs text-gray-400 uppercase tracking-wider font-bold mb-1">Total Amount</div>
                                <div className="text-xl font-bold text-primary-700 dark:text-primary-400">{currency}{sale.totalAmount.toFixed(2)}</div>
                             </div>
                             <div className="text-right hidden sm:block">
                                <div className="text-xs text-gray-400 uppercase tracking-wider font-bold mb-1">Items</div>
                                <div className="text-lg font-medium text-gray-700 dark:text-gray-300">{sale.items.reduce((acc, i) => acc + i.cartQuantity, 0)}</div>
                             </div>
                        </div>
                    </div>
                ))}
            </div>
         )}
      </div>

      {/* Bill/Receipt Modal */}
      {selectedSale && (
        <div className="fixed inset-0 bg-gray-900/80 backdrop-blur-sm z-50 flex items-center justify-center p-4 pt-20">
             <div className="relative w-full max-w-[210mm] bg-white shadow-2xl rounded-lg flex flex-col h-fit min-h-[500px]">

                {/* Header Actions */}
                <div className="absolute -top-12 left-0 w-full flex justify-between items-center print:hidden px-1">
                    <div className="bg-white p-2 rounded-lg shadow flex gap-2 overflow-x-auto max-w-[60%]">
                        <button onClick={() => setReceiptTemplate('standard')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'standard' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Standard</button>
                        <button onClick={() => setReceiptTemplate('thermal')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'thermal' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Thermal</button>
                        <button onClick={() => setReceiptTemplate('modern')} className={`px-3 py-1 text-xs font-bold rounded whitespace-nowrap ${receiptTemplate === 'modern' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700'}`}>Modern</button>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => setSelectedSale(null)} className="bg-white p-2 md:p-3 rounded-full text-gray-600 hover:text-red-600 shadow-lg hover:bg-gray-100 transition">
                            <X size={20} />
                        </button>
                        <button onClick={printReceipt} className="bg-primary-600 p-2 md:p-3 rounded-full text-white shadow-lg hover:bg-primary-700 transition">
                            <Printer size={20} />
                        </button>
                    </div>
                </div>

                {/* Printable Content Container */}
                <div id="printable-area" className="flex-1 bg-white rounded-lg overflow-hidden">
                    {receiptTemplate === 'standard' && renderStandardReceipt()}
                    {receiptTemplate === 'thermal' && renderThermalReceipt()}
                    {receiptTemplate === 'modern' && renderModernReceipt()}
                </div>
             </div>
        </div>
      )}
    </div>
  );
};

