  updateMedicine: (id: string, updates: Partial<Medicine>) => void;
  deleteMedicine: (id: string) => void;
  processSale: (sale: Sale) => void;
  addOrder: (order: Order) => void;
  updateStock: (id: string, qtyChange: number) => void;
  receiveOrder: (orderId: string, receivedItems?: Medicine[]) => void;
  importData: (jsonData: string) => void;
  exportData: () => string;
  formatDate: (dateStr: string) => string;
  updateBusinessConfig: (config: BusinessConfig) => void;
  togglePaidStatus: () => void;
  toggleDarkMode: () => void;
  initializeBusinessData: (type: BusinessType) => void;
  addCategory: (name: string, gst?: number) => void;
  updateCategory: (id: string, updates: Partial<Category>) => void;
  generateInvoiceId: () => string;
