export const PharmacyProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [inventorySearchTerm, setInventorySearchTerm] = useState('');
  const [businessConfig, setBusinessConfig] = useState<BusinessConfig | null>(null);
  const [isPaid, setIsPaid] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [theme, setTheme] = useState<AppTheme>('teal');
  const [categories, setCategories] = useState<Category[]>([]);

  // Apply Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Apply Theme Colors
  useEffect(() => {
    const root = document.documentElement;
    const colors = THEME_COLORS[theme];
    Object.entries(colors).forEach(([shade, value]) => {
      root.style.setProperty(`--c-primary-${shade}`, value as string);
    });
    if (theme === 'gradient') {
      document.body.classList.add('theme-gradient');
    } else {
      document.body.classList.remove('theme-gradient');
    }
  }, [theme]);

  // Auth Methods (Mock)
  const login = async (email: string, password: string) => {
    return new Promise<void>((resolve, reject) => {
        setTimeout(() => {
            if (email && password) {
                setUser({ name: 'Demo User', email });
                resolve();
            } else {
                reject('Invalid credentials');
            }
        }, 1000);
    });
  };

  const signup = async (name: string, email: string, password: string) => {
    return new Promise<void>((resolve, reject) => {
        setTimeout(() => {
            if (name && email && password) {
                setUser({ name, email });
                resolve();
            } else {
                reject('Please fill all fields');
            }
        }, 1000);
    });
  };

  const logout = () => {
    setUser(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const toggleDarkMode = () => setIsDarkMode(prev => !prev);
  const togglePaidStatus = () => setIsPaid(prev => !prev);

  // Generate Sequential Invoice ID
  const generateInvoiceId = () => {
    // Look at the latest sale (assuming new sales are added to the beginning)
    // If sales are not sorted, we might need to find max.
    // Assuming standard usage where sales[0] is the most recent.
    let lastId = 'INV-0000';
    if (sales.length > 0) {
        // Find the sale with the highest ID number
        const maxIdSale = sales.reduce((prev, current) => {
            const prevNum = parseInt(prev.id.replace('INV-', '')) || 0;
            const currNum = parseInt(current.id.replace('INV-', '')) || 0;
            return currNum > prevNum ? current : prev;
        });
        lastId = maxIdSale.id;
    }

    // Extract number part
    const numPart = parseInt(lastId.replace('INV-', ''));
    if (isNaN(numPart)) return `INV-0001`; // Fallback if format is different

    const nextNum = numPart + 1;
    return `INV-${String(nextNum).padStart(4, '0')}`;
  };

  // --- GST CASCADE LOGIC ---
  const updateBusinessConfig = (config: BusinessConfig) => {
    setBusinessConfig(prevConfig => {
        // If Global GST changed, cascade to everything
        if (prevConfig && config.details.defaultGst !== prevConfig.details.defaultGst) {
            const newGst = config.details.defaultGst;

            // 1. Update Categories
            setCategories(prevCats => prevCats.map(c => ({ ...c, gst: newGst })));

            // 2. Update Inventory
            setInventory(prevInv => prevInv.map(i => ({ ...i, gst: newGst })));

            alert(`System-wide GST updated to ${newGst}%. All categories and products have been updated.`);
        }
        return config;
    });
  };

  const initializeBusinessData = (type: BusinessType) => {
    const createCats = (names: string[], defaultGst: number) => names.map((name, i) => ({ id: `${i}`, name, gst: defaultGst }));

    switch (type) {
      case 'PHARMACY': 
        setInventory(PHARMACY_DATA); 
        setCategories(createCats(['Antibiotic', 'Analgesic', 'Antihistamine', 'Supplement', 'Syrup', 'Tablet', 'Injection'], 12));
        break;
      case 'RESTAURANT': 
      case 'CAFE': 
        setInventory(RESTAURANT_DATA); 
        setCategories(createCats(['Starter', 'Main Course', 'Beverage', 'Dessert', 'Side Dish'], 5));
        break;
      case 'RETAIL': 
      case 'GROCERY': 
        setInventory(RETAIL_DATA); 
        setCategories(createCats(['Men', 'Women', 'Kids', 'Footwear', 'Accessories', 'Electronics'], 12));
        break;
      default: 
        setInventory([]);
        setCategories([]);
    }
    setSales([]);
    setOrders([]);
  };

  const addCategory = (name: string, gst?: number) => {
    const finalGst = gst !== undefined ? gst : (businessConfig?.details.defaultGst || 0);
    if (!categories.some(c => c.name.toLowerCase() === name.toLowerCase())) {
      setCategories(prev => [...prev, { id: `cat-${Date.now()}`, name, gst: finalGst }]);
    }
  };

  const updateCategory = (id: string, updates: Partial<Category>) => {
    // 1. Update the category itself
    setCategories(prev => {
        const cat = prev.find(c => c.id === id);
        if (!cat) return prev;

        // 2. If GST changed, cascade to products in this category
        if (updates.gst !== undefined && updates.gst !== cat.gst) {
             setInventory(inv => inv.map(item => 
                 item.category === cat.name ? { ...item, gst: updates.gst! } : item
             ));
        }
        // 2b. If Name changed, update products linked to old name
        if (updates.name && updates.name !== cat.name) {
             setInventory(inv => inv.map(item => 
                 item.category === cat.name ? { ...item, category: updates.name! } : item
             ));
        }

        return prev.map(c => c.id === id ? { ...c, ...updates } : c);
    });
  };

  const addMedicine = (med: Medicine) => {
    setInventory(prev => [...prev, med]);
  };

  const updateMedicine = (id: string, updates: Partial<Medicine>) => {
    setInventory(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const deleteMedicine = (id: string) => {
    setInventory(prev => prev.filter(item => item.id !== id));
  };

  const updateStock = (id: string, qtyChange: number) => {
    setInventory(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: item.quantity + qtyChange } : item
    ));
  };

  const processSale = (sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    sale.items.forEach(item => {
      updateStock(item.id, -item.cartQuantity);
    });
  };

  const addOrder = (order: Order) => setOrders(prev => [order, ...prev]);

  const receiveOrder = (orderId: string, receivedItems?: Medicine[]) => {
    if (receivedItems && receivedItems.length > 0) {
      setInventory(prev => {
        const newInventory = [...prev];
        receivedItems.forEach(newItem => {
          const existingIndex = newInventory.findIndex(i => 
            i.name.toLowerCase() === newItem.name.toLowerCase() && 
            i.batchNumber === newItem.batchNumber &&
            i.expiryDate === newItem.expiryDate &&
            i.mrp === newItem.mrp &&
            i.purchasePrice === newItem.purchasePrice
          );

          if (existingIndex >= 0) {
            newInventory[existingIndex].quantity += newItem.quantity;
          } else {
            newInventory.push(newItem);
          }
        });
        return newInventory;
      });
    }

    setOrders(prev => prev.map(order => {
      if (order.id === orderId) {
        return { ...order, status: 'Completed' };
      }
      return order;
    }));
  };

  const exportData = () => JSON.stringify({ inventory, sales, orders, businessConfig, categories, theme }, null, 2);

  const importData = (jsonData: string) => {
    try {
      const data = JSON.parse(jsonData);
      if (data.inventory) setInventory(data.inventory);
      if (data.sales) setSales(data.sales);
      if (data.orders) setOrders(data.orders);

      // Backward compatibility for Categories
      if (data.categories) {
          if (data.categories.length > 0 && typeof data.categories[0] === 'string') {
              // Convert legacy string array to object array
              const defaultGst = data.businessConfig?.details?.defaultGst || 0;
              const convertedCats = (data.categories as string[]).map((name, i) => ({
                  id: `cat-${i}`,
                  name: name,
                  gst: defaultGst
              }));
              setCategories(convertedCats);
          } else {
              setCategories(data.categories);
          }
      }

      if (data.businessConfig) setBusinessConfig(data.businessConfig);
      if (data.theme) setTheme(data.theme);
      alert('Data restored successfully!');
    } catch (e) {
      alert('Invalid backup file');
    }
  };

  return (
    <PharmacyContext.Provider value={{
      user, login, signup, logout,
      inventory, sales, orders, categories, currentView, inventorySearchTerm, businessConfig, isPaid, isDarkMode, theme,
      setTheme, setInventorySearchTerm, setCurrentView, addMedicine, updateMedicine, deleteMedicine,
      processSale, addOrder, updateStock, receiveOrder, exportData, importData, formatDate,
      updateBusinessConfig, togglePaidStatus, toggleDarkMode, initializeBusinessData, addCategory, updateCategory,
      generateInvoiceId
    }}>
      {children}
    </PharmacyContext.Provider>
  );
};

export const usePharmacy = () => {
  const context = useContext(PharmacyContext);
  if (!context) throw new Error('usePharmacy must be used within a PharmacyProvider');
  return context;
};

