const AppContent: React.FC = () => {
  const { currentView, businessConfig, user } = usePharmacy();

  // 1. If not authenticated, show Auth screen
  if (!user) {
    return <Auth />;
  }

  // 2. If authenticated but no business config, show Onboarding
  if (!businessConfig) {
    return <Onboarding />;
  }

  // 3. Authenticated and Configured: Show Main App
  const renderView = () => {
    switch (currentView) {
      case AppView.DASHBOARD:
        return <Dashboard />;
      case AppView.INVENTORY:
        return <Inventory />;
      case AppView.POS:
        return <POS />;
      case AppView.AI_SCANNER:
        return <PrescriptionScanner />;
      case AppView.ORDERS:
        return <Orders />;
      case AppView.SALES_HISTORY:
        return <SalesHistory />;
      case AppView.INSIGHTS:
        return <DataInsights />;
      case AppView.CONFIGURATION:
        return <Configuration />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout>
      <div className="max-w-7xl mx-auto h-full">
        {renderView()}
      </div>
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <PharmacyProvider>
      <AppContent />
    </PharmacyProvider>
  );
