import { GoogleGenAI, Type } from "@google/genai";

// Helper to convert file to base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const analyzePrescription = async (imageFile: File, apiKey: string) => {
  try {
    if (!apiKey) throw new Error("Gemini API Key is required");
    const ai = new GoogleGenAI({ apiKey });

    const base64Data = await fileToGenerativePart(imageFile);

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: imageFile.type,
              data: base64Data
            }
          },
          {
            text: `Analyze this image (prescription or product list). Extract the items.
            Return a JSON object with a list of items/medicines, including their name, dosage/size (if visible), and instructions/notes.
            Also provide a brief summary note.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            medicines: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  dosage: { type: Type.STRING },
                  instructions: { type: Type.STRING }
                }
              }
            },
            notes: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

export const analyzeBusinessData = async (salesData: any[], inventoryData: any[], businessType: string, apiKey: string) => {
  try {
    if (!apiKey) throw new Error("Gemini API Key is required");
    const ai = new GoogleGenAI({ apiKey });

    // We limit data size to avoid token limits in this demo
    const recentSales = salesData.slice(0, 50); 
    const inventorySummary = inventoryData.map((i: any) => ({ name: i.name, qty: i.quantity, category: i.category })).slice(0, 100);

    const prompt = `
      Act as a business analyst for a ${businessType}.
      Here is the recent sales data: ${JSON.stringify(recentSales)}
      Here is the inventory summary: ${JSON.stringify(inventorySummary)}

      Provide a strategic analysis in JSON format containing:
      1. topSelling: List of top 3 performing items.
      2. lowStockAlerts: Items that need immediate restocking based on sales velocity.
      3. deadStock: Items that are not selling.
      4. recommendations: A paragraph of actionable advice to increase profit and efficiency.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            topSelling: { type: Type.ARRAY, items: { type: Type.STRING } },
            lowStockAlerts: { type: Type.ARRAY, items: { type: Type.STRING } },
            deadStock: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendations: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Error analyzing business data:", error);
    throw error;
  }
};

