                    </div>
                    <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.fields.showExpiry ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
                        {formData.fields.showExpiry && <Check size={14} />}
                    </div>
                </div>

                <div 
                    onClick={() => handleFieldToggle('showDoctor')}
                    className={`flex items-center justify-between p-4 rounded-xl border-2 cursor-pointer transition ${
                        formData.fields.showDoctor 
                        ? 'border-primary-500 bg-primary-50 dark:bg-gray-800/80 shadow-inner' 
                        : 'border-gray-100 dark:border-gray-700'
                    }`}
                    style={formData.fields.showDoctor ? { borderColor: 'var(--c-primary-500)' } : {}}
                >
                    <div>
                        <h4 className={`font-bold text-sm ${formData.fields.showDoctor ? 'text-primary-700 dark:text-primary-400' : 'text-gray-800 dark:text-white'}`}>Doctor / Ref Field</h4>
                    </div>
                    <div className={`w-5 h-5 rounded flex items-center justify-center ${formData.fields.showDoctor ? 'bg-primary-500 text-white' : 'bg-gray-200 dark:bg-gray-700'}`}>
                        {formData.fields.showDoctor && <Check size={14} />}
