          </div>
        </div>
      </div>
    </div>
  );
};

export default Configuration;

import React, { useState } from 'react';
import { Upload, Sparkles, AlertTriangle, FileText, CheckCircle, Lock } from 'lucide-react';
import { analyzePrescription } from '../services/geminiService';
import { PrescriptionAnalysis } from '../types';
import { usePharmacy } from '../services/context/PharmacyContext';

const PrescriptionScanner: React.FC = () => {
  const { isPaid, businessConfig } = usePharmacy();
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<PrescriptionAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
      setResult(null);
      setError(null);
    }
  };

  const handleAnalyze = async () => {
    if (!file) return;

    const apiKey = businessConfig?.details.geminiApiKey;
    if (!apiKey) {
        setError("Please configure your Gemini API Key in Settings to use this feature.");
        return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const data = await analyzePrescription(file, apiKey);
      setResult(data);
    } catch (err) {
      setError("Failed to analyze image. Please try again with a clearer image or check your API Key.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isPaid) {
      return (
        <div className="h-full flex flex-col items-center justify-center p-8 text-center bg-gray-50 rounded-2xl border border-gray-200 m-4 relative overflow-hidden">
             <div className="absolute inset-0 bg-gradient-to-br from-primary-500/5 to-blue-500/5"></div>
             <div className="bg-white p-4 rounded-full shadow-lg mb-6 z-10">
                <Lock size={48} className="text-gray-400" />
            </div>
            <h2 className="text-3xl font-bold text-gray-800 mb-2 z-10">AI Prescription Scanner</h2>
            <p className="text-gray-500 max-w-md mb-8 z-10">
                Upgrade to Pro to unlock advanced AI image analysis. Automatically digitize prescriptions and handwritten notes instantly.
            </p>
            <div className="flex gap-4 z-10 opacity-75 grayscale">
                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center w-32">
                    <FileText className="text-primary-500 mb-2" />
                    <span className="text-xs font-bold text-gray-600">Scan Rx</span>
                 </div>
                 <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center w-32">
                    <Sparkles className="text-blue-500 mb-2" />
                    <span className="text-xs font-bold text-gray-600">AI Extract</span>
                 </div>
            </div>
            <p className="mt-8 text-sm text-gray-400 z-10">Premium Feature</p>
        </div>
      );
  }

  return (
    <div className="p-4 h-full flex flex-col md:flex-row gap-6">
      {/* Upload Section */}
      <div className="w-full md:w-1/2 flex flex-col gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <Upload size={24} className="text-primary-600"/> Upload Prescription
          </h2>

          <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 flex flex-col items-center justify-center text-center bg-gray-50 h-64 relative">
            {preview ? (
              <img src={preview} alt="Preview" className="max-h-full max-w-full object-contain rounded" />
            ) : (
              <div className="text-gray-400">
                <FileText size={48} className="mx-auto mb-2" />
                <p>Click to upload or drag image here</p>
              </div>
            )}
            <input 
              type="file" 
              accept="image/*"
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
          </div>

          <button
            onClick={handleAnalyze}
            disabled={!file || isAnalyzing}
            className={`w-full mt-6 py-3 rounded-lg font-bold text-white flex justify-center items-center gap-2 transition ${!file ? 'bg-gray-300 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-primary-600 hover:from-blue-700 hover:to-primary-700 shadow-md'}`}
          >
            {isAnalyzing ? (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                Analyzing with Gemini...
              </>
            ) : (
              <>
                <Sparkles size={20} /> Analyze Prescription
              </>
            )}
          </button>

          <p className="text-xs text-gray-500 mt-4 text-center">
            Supported formats: JPG, PNG. Ensure handwriting is legible for best AI results.
          </p>
        </div>
      </div>

      {/* Results Section */}
      <div className="w-full md:w-1/2">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full flex flex-col">
          <h2 className="text-xl font-bold mb-4 text-gray-800">Analysis Results</h2>

          {error && (
            <div className="bg-red-50 text-red-700 p-4 rounded-lg flex items-center gap-2">
              <AlertTriangle size={20} />
              {error}
            </div>
          )}

          {!result && !error && !isAnalyzing && (
            <div className="flex-1 flex flex-col items-center justify-center text-gray-400 text-center p-8">
              <Sparkles size={48} className="mb-4 text-gray-200" />
              <p>Upload a prescription and let Gemini AI extract medicine details for you.</p>
            </div>
          )}

          {result && (
            <div className="flex-1 overflow-auto space-y-4">
              {/* Summary Note */}
              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
                <h3 className="font-semibold text-blue-800 text-sm mb-1">AI Note</h3>
                <p className="text-sm text-blue-700">{result.notes || "Analysis complete."}</p>
              </div>

              {/* Medicines List */}
              <div className="space-y-3">
                <h3 className="font-semibold text-gray-700">Detected Medicines</h3>
                {result.medicines && result.medicines.length > 0 ? (
                  result.medicines.map((med, idx) => (
                    <div key={idx} className="border border-gray-200 rounded-lg p-3 hover:shadow-md transition bg-gray-50">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-primary-700">{med.name}</h4>
                        <span className="bg-primary-100 text-primary-800 text-xs px-2 py-1 rounded-full">{med.dosage}</span>
                      </div>
                      <p className="text-sm text-gray-600 mt-2 flex items-center gap-1">
                        <CheckCircle size={14} className="text-primary-500"/> {med.instructions}
                      </p>
                    </div>
                  ))
                ) : (
                  <p className="text-gray-500 italic">No specific medicines detected.</p>
                )}
              </div>

              <div className="mt-4 pt-4 border-t">
                 <button className="w-full py-2 border border-primary-600 text-primary-600 rounded-lg font-medium hover:bg-primary-50">
                    Add All to Cart (Demo)
                 </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PrescriptionScanner;

import React, { useState } from 'react';
import { usePharmacy } from '../services/context/PharmacyContext';
import { analyzeBusinessData } from '../services/geminiService';
import { GeminiAnalysisResult } from '../types';
import { Sparkles, TrendingUp, AlertTriangle, Package, Lock } from 'lucide-react';

const DataInsights: React.FC = () => {
  const { inventory, sales, businessConfig, isPaid } = usePharmacy();
  const [isLoading, setIsLoading] = useState(false);
  const [analysis, setAnalysis] = useState<GeminiAnalysisResult | null>(null);

  const handleAnalyze = async () => {
    const apiKey = businessConfig?.details.geminiApiKey;
    if (!apiKey) {
        alert("Please configure your Gemini API Key in Settings to use this feature.");
        return;
    }

    setIsLoading(true);
    try {
      const result = await analyzeBusinessData(sales, inventory, businessConfig?.type || 'Business', apiKey);
      setAnalysis(result);
    } catch (error) {
      alert("Failed to generate insights. Please check your API Key and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!isPaid) {
    return (
      <div className="p-8 h-full flex flex-col items-center justify-center text-center bg-gray-50 dark:bg-gray-800 rounded-2xl border border-gray-200 dark:border-gray-700 m-4 relative overflow-hidden transition-colors">
        <div className="absolute inset-0 bg-gradient-to-br from-purple-500/5 to-primary-500/5 dark:from-purple-900/20 dark:to-primary-900/20"></div>
        <div className="bg-white dark:bg-gray-700 p-4 rounded-full shadow-lg mb-6 z-10">
            <Lock size={48} className="text-gray-400 dark:text-gray-300" />
        </div>
        <h2 className="text-3xl font-bold text-gray-800 dark:text-white mb-2 z-10">Premium Business Insights</h2>
        <p className="text-gray-500 dark:text-gray-400 max-w-md mb-8 z-10">
           Unlock deep AI analysis of your sales trends, inventory health, and receive actionable growth recommendations powered by Gemini.
        </p>
        <div className="flex gap-4 z-10">
             <div className="bg-white dark:bg-gray-700 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-600 flex flex-col items-center w-32">
                <TrendingUp className="text-primary-500 dark:text-primary-400 mb-2" />
                <span className="text-xs font-bold text-gray-600 dark:text-gray-300">Sales Forecast</span>
             </div>
             <div className="bg-white dark:bg-gray-700 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-600 flex flex-col items-center w-32">
                <AlertTriangle className="text-orange-500 dark:text-orange-400 mb-2" />
                <span className="text-xs font-bold text-gray-600 dark:text-gray-300">Dead Stock</span>
             </div>
        </div>
        <p className="mt-8 text-sm text-gray-400 dark:text-gray-500 z-10">Please upgrade to access this feature.</p>
      </div>
    );
  }

  return (
    <div className="p-6 h-full flex flex-col bg-gray-50/50 dark:bg-gray-900/50">
      <div className="flex justify-between items-center mb-6">
        <div>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <Sparkles className="text-purple-600 dark:text-purple-400" /> AI Business Analyst
            </h2>
            <p className="text-gray-500 dark:text-gray-400 text-sm">Powered by Gemini Pro</p>
        </div>
        {!analysis && !isLoading && (
            <button 
                onClick={handleAnalyze}
                className="bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:shadow-xl transition transform hover:scale-105 flex items-center gap-2"
            >
                <Sparkles size={18} /> Generate Report
            </button>
        )}
      </div>

      {isLoading && (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-500 dark:text-gray-400">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mb-4"></div>
            <p>Analyzing {sales.length} sales and {inventory.length} inventory items...</p>
        </div>
      )}

      {analysis && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 overflow-y-auto pb-10">
            {/* Recommendations */}
            <div className="col-span-1 md:col-span-2 bg-gradient-to-r from-purple-50 to-indigo-50 dark:from-purple-900/20 dark:to-indigo-900/20 p-6 rounded-2xl border border-purple-100 dark:border-purple-900/30">
                <h3 className="font-bold text-purple-900 dark:text-purple-300 text-lg mb-2 flex items-center gap-2">
                    <Sparkles size={20}/> AI Recommendations
                </h3>
                <p className="text-purple-800 dark:text-purple-200 leading-relaxed">
                    {analysis.recommendations}
                </p>
            </div>

            {/* Top Selling */}
            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700">
                <h3 className="font-bold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                    <TrendingUp className="text-green-500"/> Top Performers
                </h3>
                <ul className="space-y-2">
                    {analysis.topSelling.map((item, i) => (
                        <li key={i} className="flex items-center gap-3 bg-green-50 dark:bg-green-900/20 p-3 rounded-lg text-green-800 dark:text-green-300 text-sm font-medium">
