                            {item}
                        </li>
                    ))}
                </ul>
            </div>

            {/* Alerts */}
            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700">
                <h3 className="font-bold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                    <AlertTriangle className="text-orange-500"/> Restock Alerts
                </h3>
                {analysis.lowStockAlerts.length > 0 ? (
                    <ul className="space-y-2">
                        {analysis.lowStockAlerts.map((item, i) => (
                            <li key={i} className="flex items-center gap-3 bg-orange-50 dark:bg-orange-900/20 p-3 rounded-lg text-orange-800 dark:text-orange-300 text-sm font-medium">
                                <AlertTriangle size={14} />
                                {item}
                            </li>
                        ))}
                    </ul>
                ) : <p className="text-gray-400 italic">No immediate alerts.</p>}
            </div>

             {/* Dead Stock */}
             <div className="col-span-1 md:col-span-2 bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700">
                <h3 className="font-bold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                    <Package className="text-gray-400"/> Slow Moving / Dead Stock
                </h3>
                <div className="flex flex-wrap gap-2">
                    {analysis.deadStock.map((item, i) => (
                         <span key={i} className="bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 px-3 py-1 rounded-full text-sm border border-gray-200 dark:border-gray-600">
                            {item}
                         </span>
                    ))}
                </div>
            </div>

             <button onClick={() => setAnalysis(null)} className="col-span-1 md:col-span-2 text-center text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 p-4">
                Clear Report
            </button>
        </div>
      )}
    </div>
  );
};

export default DataInsights;

